const AI_SAFETY_BUFFER = 600;
const SABOTAGE_RUMORS_MULTIPLIER = 0.8;
const SABOTAGE_MARKET_PANIC_MULTIPLIER = 0.65;
const SABOTAGE_CHALLENGE_PENALTY = 0.12;
const SABOTAGE_ICON = "!";

const getDebuffDisplayName = (type: string) => {
  const action = SABOTAGE_ACTIONS.find(candidate => candidate.id === type);
  if (action) return action.name;
  return type.replace(/_/g, ' ');
};

const getEquipmentEffects = (equipment: string[] = []) => {
  const effects = {
    travelDiscount: 0,
    xpBonus: 0,
    challengeBonus: {} as Record<string, number>
  };

  equipment.forEach(itemId => {
    const item = SHOP_ITEMS.find(candidate => candidate.id === itemId);
    if (!item) return;
    if (item.effects?.travelDiscount) {
      effects.travelDiscount += item.effects.travelDiscount;
    }
    if (item.effects?.xpBonus) {
      effects.xpBonus += item.effects.xpBonus;
    }
    if (item.effects?.challengeBonus) {
      Object.entries(item.effects.challengeBonus).forEach(([type, bonus]) => {
        effects.challengeBonus[type] = (effects.challengeBonus[type] || 0) + bonus;
      });
    }
  });

  effects.travelDiscount = Math.min(0.5, effects.travelDiscount);
  effects.xpBonus = Math.min(0.5, effects.xpBonus);
  return effects;
};

const hasActiveDebuff = (debuffs: Array<{ type: string; remainingDays: number }> | undefined, type: string) => {
  if (!Array.isArray(debuffs)) return false;
  return debuffs.some(debuff => debuff.type === type && debuff.remainingDays > 0);
};

const isTravelBlocked = (debuffs: Array<{ type: string; remainingDays: number }> | undefined) => {
  return hasActiveDebuff(debuffs, 'customs_hold') || hasActiveDebuff(debuffs, 'border_lockdown');
};

const getSabotageSellMultiplier = (debuffs: Array<{ type: string; remainingDays: number }> | undefined) => {
  if (hasActiveDebuff(debuffs, 'market_panic')) return SABOTAGE_MARKET_PANIC_MULTIPLIER;
  if (hasActiveDebuff(debuffs, 'rumors')) return SABOTAGE_RUMORS_MULTIPLIER;
  return 1;
};

const getSabotageChallengePenalty = (debuffs: Array<{ type: string; remainingDays: number }> | undefined) => {
  return hasActiveDebuff(debuffs, 'challenge_jitters') ? SABOTAGE_CHALLENGE_PENALTY : 0;
};

const isEquipmentJammed = (debuffs: Array<{ type: string; remainingDays: number }> | undefined) => {
  return hasActiveDebuff(debuffs, 'gear_jam');
};

// V6.7 Phase 3c: all sabotage-applied debuff types, used by the Team Initiative "sabotage
// protection" spend effect to strip only sabotage-caused debuffs (never anything else).
const SABOTAGE_DEBUFF_TYPES = ['customs_hold', 'border_lockdown', 'market_panic', 'rumors', 'challenge_jitters', 'gear_jam'];

const tickDebuffs = (debuffs: Debuff[] = []) => {
  return debuffs
    .map(debuff => ({ ...debuff, remainingDays: debuff.remainingDays - 1 }))
    .filter(debuff => debuff.remainingDays > 0);
};

const upsertDebuff = (debuffs: Debuff[] = [], type: string, duration: number) => {
  const normalized = debuffs.filter(debuff => debuff.remainingDays > 0);
  const existing = normalized.find(debuff => debuff.type === type);
  if (existing) {
    return normalized.map(debuff =>
      debuff.type === type ? { ...debuff, remainingDays: Math.max(debuff.remainingDays, duration) } : debuff
    );
  }
  return [...normalized, { type, remainingDays: duration }];
};

// =========================================
// ADVANCED LOAN SYSTEM HELPER FUNCTIONS
// =========================================

const calculateCreditScore = (player: any, gameState: any): number => {
  let score = 50; // Base score

  const loanHistory = player.loanHistory || { totalTaken: 0, totalRepaid: 0, defaultCount: 0, earlyRepaymentCount: 0 };
  const advancedLoans = player.advancedLoans || [];

  // Repayment history (±30 points)
  if (loanHistory.totalTaken > 0) {
    const repaymentRate = loanHistory.totalRepaid / loanHistory.totalTaken;
    score += Math.floor(repaymentRate * 30) - 15;
  }

  // Early repayments (+10 max)
  score += Math.min(10, loanHistory.earlyRepaymentCount * 2);

  // Defaults (-20 per default)
  score -= loanHistory.defaultCount * 20;

  // Net worth (±20 points)
  const netWorth = player.money + (player.inventory?.length || 0) * 50;
  if (netWorth > 5000) score += 20;
  else if (netWorth > 3000) score += 10;
  else if (netWorth > 1000) score += 0;
  else if (netWorth > 500) score -= 10;
  else score -= 20;

  // Active loans penalty (-5 per loan)
  score -= advancedLoans.length * 5;

  // Days without bankruptcy (+1 per 3 days, max +10)
  const daysSinceBankruptcy = player.daysSinceLastBankruptcy || 0;
  score += Math.min(10, Math.floor(daysSinceBankruptcy / 3));

  // Challenge completion rate (+10 max)
  const totalChallenges = Object.values(REGIONS).reduce((sum: number, region: any) => sum + region.challenges.length, 0);
  const completedChallenges = player.challengesCompleted?.length || 0;
  if (completedChallenges > 0) {
    const completionRate = completedChallenges / totalChallenges;
    score += Math.floor(completionRate * 10);
  }

  // Clamp to 0-100
  return Math.max(0, Math.min(100, score));
};

const getCreditScoreRange = (score: number) => {
  return CREDIT_SCORE_RANGES.find(range => score >= range.min && score <= range.max) || CREDIT_SCORE_RANGES[4];
};

const calculateLoanInterest = (loan: AdvancedLoan, creditScoreMultiplier: number, accrualRate: number): number => {
  const dailyRate = loan.actualInterestRate / loan.term;
  return loan.amount * dailyRate * accrualRate;
};

const getEarlyRepaymentDiscount = (): number => {
  return 0.5; // 50% discount on interest for early repayment
};

const checkLoanEvent = (player: any, settings: GameSettingsState): typeof LOAN_EVENTS[0] | null => {
  if (!settings.loanEventsEnabled) return null;

  for (const event of LOAN_EVENTS) {
    if (event.triggerCondition(player)) {
      // Random chance to trigger (30% when conditions met)
      if (Math.random() < 0.3) {
        return event;
      }
    }
  }
  return null;
};

// =========================================
// ADAPTIVE AI HELPER FUNCTIONS
// =========================================

const calculateInventoryMarketValue = (
  inventory: string[] | null | undefined,
  resourcePrices?: Record<string, number> | null
) => {
  return (inventory || []).reduce((total, resource) => {
    const livePrice = resourcePrices?.[resource];
    const marketPrice = typeof livePrice === 'number' && isFinite(livePrice)
      ? livePrice
      : getResourceMarketPrice(resource);
    return total + marketPrice;
  }, 0);
};

const calculateNetWorth = (player: any, resourcePrices?: Record<string, number> | null): number => {
  const money = player?.money || 0;
  const inventoryValue = calculateInventoryMarketValue(player?.inventory || [], resourcePrices);
  const investmentsValue = (player?.investments || []).reduce((sum: number, regionCode: string) => {
    return sum + (REGIONAL_INVESTMENTS[regionCode]?.cost || 0);
  }, 0);
  const equipmentValue = (player?.equipment || []).reduce((sum: number, itemId: string) => {
    return sum + (SHOP_ITEMS.find(item => item.id === itemId)?.cost || 0);
  }, 0);
  return money + inventoryValue + investmentsValue + equipmentValue;
};

// V6.8 Phase B: Ratcheting Cash Vault. Base milestone ladder matching the spec's examples
// ($2k/$5k/$10k/$20k/$40k), extended indefinitely by doubling the last value, all scaled by
// vaultMilestoneSizeMultiplier so the whole ladder can shift without redefining its shape.
const VAULT_BASE_MILESTONES = [2000, 5000, 10000, 20000, 40000];
const getVaultMilestoneLadder = (multiplier: number, tierCount: number = 12): number[] => {
  const scale = isFinite(multiplier) && multiplier > 0 ? multiplier : 1.0;
  const ladder = VAULT_BASE_MILESTONES.map(value => value * scale);
  while (ladder.length < tierCount) {
    ladder.push(ladder[ladder.length - 1] * 2);
  }
  return ladder;
};

// Protected cash is a soft floor on the same actor.money field, never a second balance — this is
// the sole accessor voluntary AI spending gates should consult for affordability once the Vault is
// enabled. Returns raw money unchanged (byte-identical to today) when vaultActive is false.
const getActorSpendableCash = (actor: { money: number; protectedCash?: number }, vaultActive: boolean): number => {
  if (!vaultActive) return actor.money;
  return Math.max(0, actor.money - Math.min(actor.protectedCash || 0, actor.money));
};

// V6.8 Phase C: Team Economy Governor. All three helpers below are plain, module-level pure
// functions (not hooks) specifically so they can be called from existing functions declared at
// any point in the file — including ones declared long before the component's other Team AI
// checker cluster — without any forward-reference/TDZ concern.

// Reuses the same percentElapsed concept Phase 3b's computeEndgameAccelerationState established,
// but as a standalone calculation independent of that feature's own teamAiEndgameAccelerationEnabled
// toggle — the Governor's Endgame phase is a distinct concept that can be active even when Phase
// 3b's Endgame Acceleration feature itself is off.
const isEndgamePeriod = (day: number, totalDays: number, startPercent: number): boolean => {
  const percentElapsed = totalDays > 0 ? day / totalDays : 0;
  return percentElapsed >= startPercent;
};

// Four economic phases, computed on demand (never persisted) — only the recovery flag itself
// (ActorState.inEconomicRecovery) is persisted; everything else is derived fresh each call.
const computeEconomicPhase = (
  actor: { inEconomicRecovery?: boolean },
  spendableCash: number,
  settings: GameSettingsState,
  endgameActive: boolean
): EconomicPhase => {
  if (actor.inEconomicRecovery) return 'survival';
  if (endgameActive) return 'endgame';
  if (spendableCash >= settings.economyRecoveryTarget) return 'compounding';
  return 'accumulation';
};

const ECONOMY_RESERVE_STRENGTH_MULTIPLIER: Record<EconomyReserveStrength, number> = {
  low: 0.75,
  balanced: 1.0,
  high: 1.35
};

// The cash amount that must remain spendable for an actor's current phase — the one reserve
// calculation both spending approval and dynamic wager sizing consult.
const computeDynamicReserve = (
  phase: EconomicPhase,
  spendableCash: number,
  settings: GameSettingsState
): number => {
  const strengthMultiplier = ECONOMY_RESERVE_STRENGTH_MULTIPLIER[settings.economyReserveStrength] || 1.0;
  switch (phase) {
    case 'compounding':
      return Math.round(Math.max(settings.economyCashFloor * strengthMultiplier, spendableCash * 0.25 * strengthMultiplier));
    case 'endgame':
      return Math.round(settings.economyCashFloor * strengthMultiplier * 0.5);
    case 'survival':
    case 'accumulation':
    default:
      return Math.round(settings.economyCashFloor * strengthMultiplier);
  }
};

// Team Treasury Phase T1: recomputed once per day in advanceDay's existing per-team rebuild
// block, mirroring the Governor's/Vault's own daily-recompute precedent. Fixed by default
// (settings.teamTreasuryReserve verbatim); the optional dynamic mode scales that base by four
// separately-named, inspectable factors (never an opaque single formula) — teammate count, day
// progress, recovery-actor count, and endgame state.
const computeTeamTreasuryReserve = (
  teamActors: { inEconomicRecovery?: boolean }[],
  settings: GameSettingsState,
  day: number,
  endgameActive: boolean
): number => {
  if (!settings.teamTreasuryDynamicReserveEnabled) return settings.teamTreasuryReserve;
  const teammateCountFactor = 1 + Math.max(0, teamActors.length - 1) * 0.15;
  const dayRatioFactor = 1 + Math.min(0.5, (day / Math.max(1, settings.totalDays)) * 0.3);
  const recoveryActorFactor = 1 + teamActors.filter(a => a.inEconomicRecovery).length * 0.25;
  const endgameFactor = endgameActive ? 0.7 : 1.0;
  return Math.round(settings.teamTreasuryReserve * teammateCountFactor * dayRatioFactor * recoveryActorFactor * endgameFactor);
};

type EconomySpendCategory = 'equipment' | 'investment' | 'sabotage' | 'region_deposit' | 'travel' | 'override' | 'support';
// Team Treasury Phase T3: a pure detection/explanation classification of this turn's Governor
// activity — never a new spending mechanism, and never applied when zero Governor rejections
// occurred this turn (deliberate strategic waiting is always 'operational', regardless of what
// the AI chose to do).
type GovernorRestrictionLevel = 'operational' | 'restricted_but_operational' | 'severely_restricted' | 'governor_deadlock';

// One shared spending-approval gate, consulted as an ADDITIONAL check alongside (never replacing)
// each category's existing affordability/ROI math. Returns approved:true (a no-op) whenever the
// Governor is off, so every call site is byte-identical to today when the toggle is off.
const evaluateEconomySpendingApproval = (
  actor: { money: number; protectedCash?: number; inEconomicRecovery?: boolean },
  category: EconomySpendCategory,
  cost: number,
  settings: GameSettingsState,
  currentDay: number,
  context?: { expectedReturn?: number }
): { approved: boolean; reason: string; phase: EconomicPhase } => {
  if (!settings.teamCompetitiveAiEnabled || !settings.teamEconomyGovernorEnabled) {
    return { approved: true, reason: 'Economy Governor is off.', phase: 'accumulation' };
  }
  const spendableCash = getActorSpendableCash(actor, settings.teamCashVaultEnabled);
  const endgameActive = isEndgamePeriod(currentDay, settings.totalDays, settings.teamAiEndgameStartPercent);
  const phase = computeEconomicPhase(actor, spendableCash, settings, endgameActive);
  const reserve = computeDynamicReserve(phase, spendableCash, settings);
  if ((spendableCash - cost) < reserve) {
    return { approved: false, reason: `${phase} phase reserve of $${reserve} would be breached.`, phase };
  }
  const strictnessMultiplier = settings.economySpendingApprovalStrictness === 'strict' ? 1.5 : settings.economySpendingApprovalStrictness === 'low' ? 0.6 : 1.0;
  const hasProfitableReturn = Boolean(context?.expectedReturn && context.expectedReturn > cost * (1.15 * strictnessMultiplier));
  switch (phase) {
    case 'survival':
      if (category === 'equipment' || category === 'investment') {
        return { approved: false, reason: 'Survival phase blocks long-payback spending.', phase };
      }
      if (category === 'sabotage') {
        return { approved: false, reason: 'Survival phase blocks ordinary sabotage spending.', phase };
      }
      if (category === 'region_deposit' && settings.winCondition !== 'regions') {
        return { approved: false, reason: 'Survival phase blocks speculative region deposits.', phase };
      }
      if (category === 'travel' && !hasProfitableReturn) {
        return { approved: false, reason: 'Survival phase requires a clearly profitable travel objective.', phase };
      }
      break;
    case 'accumulation':
      if ((category === 'equipment' || category === 'investment') && !hasProfitableReturn) {
        return { approved: false, reason: 'Accumulation phase requires a clearly profitable return before committing cash.', phase };
      }
      break;
    case 'endgame':
      if ((category === 'equipment' || category === 'investment') && !(context?.expectedReturn && context.expectedReturn > cost * 2)) {
        return { approved: false, reason: 'Endgame phase deprioritizes long-payback spending.', phase };
      }
      break;
    case 'compounding':
    default:
      break;
  }
  return { approved: true, reason: `${phase} phase: approved.`, phase };
};

// Team Treasury Phase T4 (GD1): a small allow-list eligibility check for the Productive Recovery
// Ladder — never a new scoring system, and never an auto-approval. Every real gate (Governor,
// Requirements) still fully re-evaluates probability/expected-return/downside/reserve-breach for
// whichever candidate this returns true for; this only decides which candidates are worth trying.
const isRecoverySafeCandidate = (
  candidate: ScoredTeamAiDecision,
  actor: ActorState,
  settings: GameSettingsState
): boolean => {
  switch (candidate.type) {
    case 'sell':
      return true;
    case 'craft': {
      const recipe = CRAFTING_RECIPES.find(item => item.id === candidate.data?.recipeId);
      if (!recipe) return false;
      const ingredientCost = Object.entries(recipe.inputs).reduce(
        (sum, [resource, count]) => sum + getResourceMarketPrice(resource) * Number(count), 0
      );
      const sellValue = recipe.baseValue || getResourceMarketPrice(recipe.output);
      return sellValue > ingredientCost;
    }
    case 'challenge': {
      const chance = typeof candidate.data?.successChance === 'number' ? candidate.data.successChance : 0;
      return chance >= settings.guaranteedRecoveryMinimumChallengeProbability;
    }
    case 'travel':
      return Boolean(candidate.plan?.expectedValue && candidate.plan.expectedValue > 0);
    case 'buy_market':
      return Boolean(candidate.plan?.expectedValue && candidate.plan.expectedValue > 0);
    case 'region_deposit':
      return settings.winCondition === 'regions';
    default:
      return false;
  }
};

const detectAdaptiveAiPhase = (
  playerNetWorth: number,
  aiNetWorth: number,
  playerLevel: number,
  aiLevel: number,
  playerChallenges: number,
  aiChallenges: number,
  settings: GameSettingsState
): 'normal' | 'phase1_aggressive' | 'phase2_desperate' | 'phase3_allIn' => {
  if (!settings.adaptiveAiEnabled) return 'normal';

  // Avoid division by zero
  if (playerNetWorth === 0) playerNetWorth = 1;

  const netWorthRatio = aiNetWorth / playerNetWorth;
  const levelDiff = playerLevel - aiLevel;
  const challengeDiff = playerChallenges - aiChallenges;

  // Check Phase 3 (All-In) - most desperate
  const phase3Thresholds = ADAPTIVE_AI_THRESHOLDS.phase3_allIn;
  if (
    netWorthRatio < phase3Thresholds.netWorthRatio ||
    levelDiff >= phase3Thresholds.levelDifference ||
    challengeDiff >= phase3Thresholds.challengeDifference
  ) {
    return 'phase3_allIn';
  }

  // Check Phase 2 (Desperate)
  const phase2Thresholds = ADAPTIVE_AI_THRESHOLDS.phase2_desperate;
  if (
    netWorthRatio < phase2Thresholds.netWorthRatio ||
    levelDiff >= phase2Thresholds.levelDifference ||
    challengeDiff >= phase2Thresholds.challengeDifference
  ) {
    return 'phase2_desperate';
  }

  // Check Phase 1 (Aggressive)
  const phase1Thresholds = ADAPTIVE_AI_THRESHOLDS.phase1_aggressive;
  if (
    netWorthRatio < phase1Thresholds.netWorthRatio ||
    levelDiff >= phase1Thresholds.levelDifference ||
    challengeDiff >= phase1Thresholds.challengeDifference
  ) {
    return 'phase1_aggressive';
  }

  return 'normal';
};

const updatePlayerPattern = (pattern: PlayerPattern, action: string, data: any): PlayerPattern => {
  const newPattern = { ...pattern };

  switch (action) {
    case 'sell':
      const resource = data.resource;
      newPattern.favoriteResources = {
        ...newPattern.favoriteResources,
        [resource]: (newPattern.favoriteResources[resource] || 0) + 1
      };
      break;

    case 'challenge':
      const challengeType = data.type;
      newPattern.preferredChallengeTypes = {
        ...newPattern.preferredChallengeTypes,
        [challengeType]: (newPattern.preferredChallengeTypes[challengeType] || 0) + 1
      };

      // Update average wager
      const currentAvg = newPattern.averageChallengeWager;
      const totalChallenges = Object.values(newPattern.preferredChallengeTypes).reduce((a: number, b: number) => a + b, 0);
      newPattern.averageChallengeWager = ((currentAvg * (totalChallenges - 1)) + data.wager) / totalChallenges;
      break;

    case 'travel':
      newPattern.recentTravel = [data.region, ...newPattern.recentTravel].slice(0, 10);
      break;

    case 'craft':
      newPattern.craftingFrequency += 1;
      break;
  }

  // Update risk profile based on average wager and challenge frequency
  if (newPattern.averageChallengeWager > 300) {
    newPattern.riskProfile = 'aggressive';
  } else if (newPattern.averageChallengeWager > 150) {
    newPattern.riskProfile = 'moderate';
  } else {
    newPattern.riskProfile = 'conservative';
  }

  return newPattern;
};

const getAdaptiveAiPhaseEmoji = (phase: string): string => {
  switch (phase) {
    case 'phase1_aggressive': return '😤';
    case 'phase2_desperate': return '😰';
    case 'phase3_allIn': return '🔥';
    default: return '🤖';
  }
};

const getAdaptiveAiPhaseName = (phase: string): string => {
  switch (phase) {
    case 'phase1_aggressive': return 'Aggressive';
    case 'phase2_desperate': return 'Desperate';
    case 'phase3_allIn': return 'All-In';
    default: return 'Normal';
  }
};

const processAdvancedLoans = (
  player: any,
  gameSettings: GameSettingsState,
  currentDay: number
): { updatedPlayer: any; notifications: Array<{ message: string; type: string }> } => {
  if (!gameSettings.advancedLoansEnabled) {
    return { updatedPlayer: player, notifications: [] };
  }

  const notifications: Array<{ message: string; type: string }> = [];
  let updatedPlayer = { ...player };
  let advancedLoans = [...(player.advancedLoans || [])];
  let loanHistory = { ...(player.loanHistory || { totalTaken: 0, totalRepaid: 0, defaultCount: 0, earlyRepaymentCount: 0 }) };

  const creditScore = gameSettings.creditScoreEnabled ? calculateCreditScore(player, { day: currentDay }) : 50;
  const creditRange = getCreditScoreRange(creditScore);

  // Process each loan
  const loansToRemove: string[] = [];

  advancedLoans = advancedLoans.map(loan => {
    const updatedLoan = { ...loan };

    // Decrease days remaining
    updatedLoan.daysRemaining -= 1;

    // Accrue interest
    const interestAmount = calculateLoanInterest(
      updatedLoan,
      gameSettings.creditScoreEnabled ? creditRange.multiplier : 1.0,
      gameSettings.interestAccrualRate
    );
    updatedLoan.accrued += interestAmount;

    // Check for default (term expired)
    if (updatedLoan.daysRemaining <= 0) {
      const totalOwed = updatedLoan.amount + updatedLoan.accrued;
      const penalty = totalOwed * (gameSettings.defaultPenaltyMultiplier - 1.0);

      updatedPlayer.money -= (totalOwed + penalty);
      loanHistory.defaultCount += 1;

      notifications.push({
        message: `Loan defaulted! Paid $${Math.floor(totalOwed + penalty)} (includes ${Math.floor(penalty)} penalty)`,
        type: 'error'
      });

      loansToRemove.push(loan.id);

      // Update bankruptcy tracking
      if (updatedPlayer.money < BANKRUPTCY_THRESHOLD) {
        updatedPlayer.daysSinceLastBankruptcy = 0;
      }
    }

    return updatedLoan;
  });

  // Remove defaulted loans
  advancedLoans = advancedLoans.filter(loan => !loansToRemove.includes(loan.id));

  // Update player state
  updatedPlayer.advancedLoans = advancedLoans;
  updatedPlayer.loanHistory = loanHistory;
  updatedPlayer.creditScore = creditScore;

  // Increment days since last bankruptcy
  if (updatedPlayer.money >= BANKRUPTCY_THRESHOLD) {
    updatedPlayer.daysSinceLastBankruptcy = (updatedPlayer.daysSinceLastBankruptcy || 0) + 1;
  }

  return { updatedPlayer, notifications };
};

