const normalizeAiSeed = (seed: number) => {
  const numericSeed = Number.isFinite(seed) ? Math.floor(seed) : 1;
  const normalized = numericSeed % (AI_RNG_MODULUS - 1);
  return normalized > 0 ? normalized : 1;
};

