const DEFAULT_WIN_CONDITION_TIEBREAKERS: WinMetric[] = ['netWorth', 'money', 'regions'];
const GRAND_TOUR_FINAL_REGION = 'ACT';
const GRAND_TOUR_FINAL_CHALLENGE = { name: 'National Champion', difficulty: 4, reward: 4, type: 'finale' };

const createDefaultGrandTourProgress = (): GrandTourActorProgress => ({
  stamps: [],
  finalUnlocked: false,
  finalCompleted: false
});

const createDefaultGrandTourState = (): GrandTourState => ({
  progressByActorId: {},
  winnerActorId: null,
  finalChallengeRegion: GRAND_TOUR_FINAL_REGION,
  requiredRegions: Object.keys(REGIONS)
});

const getGrandTourProgress = (state: GrandTourState | undefined | null, actorId: string): GrandTourActorProgress => {
  const progress = state?.progressByActorId?.[actorId];
  if (!progress) return createDefaultGrandTourProgress();
  const requiredRegions = state?.requiredRegions?.length ? state.requiredRegions : Object.keys(REGIONS);
  const stamps = Array.isArray(progress.stamps)
    ? Array.from(new Set(progress.stamps.filter(regionCode => requiredRegions.includes(regionCode))))
    : [];
  return {
    stamps,
    finalUnlocked: Boolean(progress.finalUnlocked) || requiredRegions.every(regionCode => stamps.includes(regionCode)),
    finalCompleted: Boolean(progress.finalCompleted)
  };
};

const normalizeGrandTourState = (value: unknown): GrandTourState => {
  const defaults = createDefaultGrandTourState();
  if (!value || typeof value !== 'object') return defaults;
  const source = value as Partial<GrandTourState>;
  const requiredRegions = Array.isArray(source.requiredRegions)
    ? Array.from(new Set(source.requiredRegions.filter(regionCode => typeof regionCode === 'string' && REGIONS[regionCode])))
    : defaults.requiredRegions;
  const normalizedRequiredRegions = requiredRegions.length > 0 ? requiredRegions : defaults.requiredRegions;
  const progressByActorId = typeof source.progressByActorId === 'object' && source.progressByActorId !== null
    ? Object.entries(source.progressByActorId).reduce<Record<string, GrandTourActorProgress>>((acc, [actorId, progress]) => {
        if (typeof actorId !== 'string') return acc;
        const rawProgress = progress as Partial<GrandTourActorProgress>;
        const stamps = Array.isArray(rawProgress?.stamps)
          ? Array.from(new Set(rawProgress.stamps.filter(regionCode => typeof regionCode === 'string' && normalizedRequiredRegions.includes(regionCode))))
          : [];
        acc[actorId] = {
          stamps,
          finalUnlocked: Boolean(rawProgress?.finalUnlocked) || normalizedRequiredRegions.every(regionCode => stamps.includes(regionCode)),
          finalCompleted: Boolean(rawProgress?.finalCompleted)
        };
        return acc;
      }, {})
    : {};
  return {
    progressByActorId,
    winnerActorId: typeof source.winnerActorId === 'string' ? source.winnerActorId : null,
    finalChallengeRegion: GRAND_TOUR_FINAL_REGION,
    requiredRegions: normalizedRequiredRegions
  };
};

const updateGrandTourProgressForChallenge = (
  state: GrandTourState | undefined | null,
  actorId: string,
  regionCode: string,
  challengeName: string
): GrandTourState => {
  const normalized = normalizeGrandTourState(state);
  if (!REGIONS[regionCode] || !actorId) return normalized;
  const current = getGrandTourProgress(normalized, actorId);
  const nextStamps = current.stamps.includes(regionCode) ? current.stamps : [...current.stamps, regionCode];
  const finalUnlocked = normalized.requiredRegions.every(requiredRegion => nextStamps.includes(requiredRegion));
  const completingFinale = regionCode === normalized.finalChallengeRegion
    && challengeName === GRAND_TOUR_FINAL_CHALLENGE.name
    && finalUnlocked;
  const nextProgress: GrandTourActorProgress = {
    stamps: nextStamps,
    finalUnlocked,
    finalCompleted: current.finalCompleted || completingFinale
  };
  return {
    ...normalized,
    progressByActorId: {
      ...normalized.progressByActorId,
      [actorId]: nextProgress
    },
    winnerActorId: normalized.winnerActorId || (nextProgress.finalCompleted ? actorId : null)
  };
};

