const DEFAULT_DONT_ASK: DontAskAgainPrefs = {
  travel: false,
  sell: false,
  challenge: false,
  endDay: false
};

function getActionDisabledReason(actionId: string, context: ActionContext): string | null {
  const {
    isPlayerTurn,
    isCompetitiveMode,
    isTeamMode,
    isShopRegion,
    player,
    selectedMode,
    settings,
    day,
    totalDays,
    activeDebuffs,
    availableChallenges,
    inventoryCount
  } = context;

  if (!isPlayerTurn && actionId !== 'settings' && actionId !== 'help' && actionId !== 'history' && actionId !== 'progress') {
    return 'Only available on your turn';
  }

  if (settings.actionLimitsEnabled && player.actionsUsedThisTurn >= settings.playerActionsPerDay && actionId !== 'endTurn') {
    return settings.allowActionOverride ? 'Action limit reached' : 'Action limit reached';
  }

  switch (actionId) {
    case 'travel':
      if (settings.sabotageEnabled && isTravelBlocked(activeDebuffs)) return 'Travel blocked by Customs Hold';
      return null;
    case 'challenges':
      if (!availableChallenges || availableChallenges.length === 0) return 'No challenges available here';
      if (player.money < MINIMUM_WAGER) return `Need $${MINIMUM_WAGER - player.money} more`;
      return null;
    case 'market':
      if (inventoryCount <= 0) return 'No resources to sell';
      return null;
    case 'resourceMarket':
      if (inventoryCount >= MAX_INVENTORY) return 'Inventory full';
      return null;
    case 'workshop': {
      const craftable = CRAFTING_RECIPES.some(recipe => Object.entries(recipe.inputs).every(([resource, count]) => (
        player.inventory.filter(item => item === resource).length >= Number(count)
      )));
      if (!craftable) return 'No craftable recipes';
      if (inventoryCount >= MAX_INVENTORY) return 'Inventory full';
      return null;
    }
    case 'shop':
      if (!settings.equipmentShopEnabled) return 'Equipment shop disabled';
      if (!isShopRegion) return 'Only available in shop regions';
      return null;
    case 'loans':
      if (!settings.advancedLoansEnabled || settings.advancedLoansAccessMode === 'ai_only') return 'Loans disabled for player';
      return null;
    case 'sabotage':
      if (!settings.sabotageEnabled) return 'Sabotage disabled';
      if (!isCompetitiveMode) return 'Only available in AI modes';
      return null;
    case 'negotiations':
      if (!settings.negotiationMode) return 'Negotiation mode disabled';
      return null;
    case 'investments':
      if (!settings.investmentsEnabled) return 'Investments disabled';
      return null;
    case 'endTurn':
      if (day >= totalDays) return 'Game has ended';
      return null;
    case 'teamAiSystems':
      if (!isTeamMode) return 'Requires Team Mode';
      if (!settings.teamModeAiSystemsEnabled) return 'Team Mode AI systems disabled';
      return null;
    case 'aiOnly':
      if (selectedMode !== 'ai' && selectedMode !== 'grand_tour' && !isTeamMode) return 'Only available in AI modes';
      return null;
    default:
      return null;
  }
}

const formatCoachMetricValue = (metric: WinMetric, value: number) => {
  return metric === 'regions' ? `${value} regions` : `$${Math.round(value).toLocaleString()}`;
};

function getWinConditionProgressSummary(context: WinConditionContext): WinConditionSummary {
  const daysRemaining = Math.max(0, context.totalDays - context.day);
  const delta = context.playerValue - context.opponentValue;
  const absGap = Math.abs(delta);
  const metricLabel = WIN_METRIC_LABELS[context.winCondition] || 'Score';
  const leaderLabel = delta === 0 ? 'Nobody' : delta > 0 ? context.playerLabel : context.opponentLabel;
  const urgency: WinConditionSummary['urgency'] = daysRemaining <= 5 || absGap > Math.max(800, context.opponentValue * 0.25)
    ? 'high'
    : daysRemaining <= 12 || absGap > Math.max(350, context.opponentValue * 0.1)
      ? 'medium'
      : 'low';
  const statusLine = delta === 0
    ? `${context.playerLabel} and ${context.opponentLabel} are tied on ${metricLabel}.`
    : `${leaderLabel} is leading on ${metricLabel}.`;
  const gapLine = delta === 0
    ? 'Score gap: tied.'
    : delta > 0
      ? `You are leading by ${formatCoachMetricValue(context.winCondition, absGap)}.`
      : `You are behind by ${formatCoachMetricValue(context.winCondition, absGap)}.`;
  const recommendation = context.winCondition === 'regions'
    ? (delta >= 0
      ? 'Protect controlled regions, reinforce close deposits, and avoid cashing out key positions.'
      : 'Focus on adjacent region control, defend your strongest region, and block the leader.')
    : context.winCondition === 'netWorth'
      ? (delta >= 0
        ? 'Protect net worth with profitable crafts, selective investments, and fewer low-value travel moves.'
        : 'Build net worth through high-margin crafts, investments, and resource sales above base price.')
      : (delta >= 0
        ? 'Protect your cash lead by selling high-value resources and avoiding risky wagers.'
        : 'Sell high-value resources, complete medium challenges, and avoid unnecessary travel.');

  return {
    title: context.isTeamMode ? 'Team Win-Condition Coach' : 'Win-Condition Coach',
    statusLine,
    gapLine,
    timeLine: `${daysRemaining} ${daysRemaining === 1 ? 'day' : 'days'} remaining.`,
    recommendation,
    urgency
  };
}

function getGroupedInventory(inventory: string[], resourcePrices: Record<string, number>): GroupedInventoryItem[] {
  const counts = (inventory || []).reduce<Record<string, number>>((acc, resource) => {
    acc[resource] = (acc[resource] || 0) + 1;
    return acc;
  }, {});

  return Object.entries(counts).map(([resource, count]) => {
    const basePrice = getResourceMarketPrice(resource);
    const currentPrice = resourcePrices[resource] || basePrice || 100;
    const usedInRecipes = CRAFTING_RECIPES
      .filter(recipe => Boolean(recipe.inputs?.[resource]))
      .map(recipe => recipe.output);
    const craftReadyRecipes = CRAFTING_RECIPES.filter(recipe => Object.entries(recipe.inputs).every(([input, required]) => (
      (counts[input] || 0) >= Number(required)
    )));
    const isCraftReady = craftReadyRecipes.some(recipe => Boolean(recipe.inputs?.[resource]));
    const neededForRecipes = CRAFTING_RECIPES
      .filter(recipe => Boolean(recipe.inputs?.[resource]) && !Object.entries(recipe.inputs).every(([input, required]) => (
        (counts[input] || 0) >= Number(required)
      )))
      .map(recipe => recipe.output);
    const valueRatio = currentPrice / Math.max(1, basePrice);
    const trendLabel = valueRatio >= 1.25
      ? 'High demand'
      : valueRatio <= 0.85
        ? 'Below base'
        : 'Stable';

    return {
      resource,
      count,
      category: RESOURCE_CATEGORIES[resource] || 'unknown',
      currentPrice,
      basePrice,
      trendLabel,
      isHighDemand: valueRatio >= 1.2,
      isCraftReady,
      usedInRecipes,
      neededForRecipes,
      valueRatio
    };
  });
}

function assignTeamAiRole(actor: ActorState, team: TeamState, context: TeamAiContext): TeamAiRole {
  const activeDirectiveTypes = new Set((context.activeDirectives || []).map(message => message.type));
  const inventoryCount = actor.inventory?.length || 0;
  const lowCash = actor.money < 400;

  if (lowCash || context.profile === 'classic' && actor.aiRoleMode === 'recovery') return 'recovery';
  if (context.profile === 'support_heavy' || context.teammateWeakness || activeDirectiveTypes.has('request_help') || activeDirectiveTypes.has('protect_me')) return 'support';
  if (context.profile === 'region_control' || context.winCondition === 'regions' || activeDirectiveTypes.has('request_cover') || activeDirectiveTypes.has('reserve_region')) return 'controller';
  if (context.profile === 'chaos_team' || (context.profile === 'competitive' && context.settings.sabotageEnabled)) return 'saboteur';
  if (context.profile === 'economy_engine' || context.craftingOpportunity || activeDirectiveTypes.has('combo_setup')) return inventoryCount >= 2 ? 'crafter' : 'earner';
  if (context.profile === 'role_based') {
    const actorIndex = Math.max(0, (team.actorIds || []).indexOf(actor.id));
    const roleCycle: TeamAiRole[] = ['earner', 'explorer', 'crafter', 'support', 'controller', 'saboteur', 'recovery'];
    return roleCycle[actorIndex % roleCycle.length];
  }
  if ((actor.visitedRegions?.length || 0) < Math.max(3, Object.keys(REGIONS).length / 2)) return 'explorer';
  return 'earner';
}

function evaluateTeamSupportAction(actor: ActorState, team: TeamState, context: TeamAiContext): AIAction | null {
  const teammates = (context.teamActors || []).filter(teammate => teammate.id !== actor.id);
  const weakest = teammates
    .slice()
    .sort((left, right) => (left.money || 0) - (right.money || 0))[0];
  if (!weakest) return null;

  const supportProfiles: TeamModeAiSystemProfile[] = ['cooperative', 'support_heavy', 'role_based'];
  const profileSupportsAid = supportProfiles.includes(context.profile);
  const safetyBuffer = Math.max(AI_SAFETY_BUFFER, 500);
  const surplus = Math.max(0, actor.money - safetyBuffer);

  if ((profileSupportsAid || context.teammateWeakness) && weakest.money < 450 && surplus >= 150) {
    const amount = Math.min(450, surplus, Math.max(150, 650 - weakest.money));
    return {
      type: 'give_cash',
      description: `Support ${weakest.displayName || weakest.name} with cash`,
      data: {
        targetActorId: weakest.id,
        amount,
        remoteAid: actor.currentRegion !== weakest.currentRegion,
        reason: `${TEAM_MODE_AI_PROFILE_LABELS[context.profile]} profile is protecting teammate liquidity.`
      }
    };
  }

  const helpfulResource = actor.inventory.find(resource => CRAFTING_RECIPES.some(recipe => {
    if (!recipe.inputs?.[resource]) return false;
    const teammateHas = weakest.inventory.filter(item => item === resource).length;
    return teammateHas < Number(recipe.inputs[resource]);
  }));
  if ((profileSupportsAid || context.profile === 'economy_engine') && helpfulResource && actor.currentRegion === weakest.currentRegion) {
    return {
      type: 'give_resource',
      description: `Share ${helpfulResource} with ${weakest.displayName || weakest.name}`,
      data: {
        targetActorId: weakest.id,
        resource: helpfulResource,
        quantity: 1,
        reason: `${helpfulResource} may help complete a team recipe.`
      }
    };
  }

  return null;
}

function chooseTeamObjective(team: TeamState, opponentTeam: TeamState | null, context: TeamAiContext): TeamGoal {
  const opponentLead = context.opponentLead || 0;
  const turn = context.currentTurn || 0;
  const targetRegion = Object.keys(REGIONS)[Math.max(0, (turn + (team.actorIds?.length || 0)) % Object.keys(REGIONS).length)];

  if (context.winCondition === 'regions' || context.profile === 'region_control') {
    return {
      id: `objective-control-${team.id}-${turn}`,
      kind: 'control',
      description: `Control ${targetRegion}`,
      priority: opponentLead > 0 ? 5 : 4,
      status: 'active',
      targetRegion,
      reason: `${REGIONS[targetRegion]?.name || targetRegion} helps region-control pressure.`
    };
  }
  if (context.teammateWeakness || context.profile === 'support_heavy' || context.profile === 'cooperative') {
    return {
      id: `objective-support-${team.id}-${turn}`,
      kind: 'support',
      description: 'Support weakest teammate',
      priority: 5,
      status: 'active',
      reason: 'Team liquidity is uneven or a teammate is at risk.'
    };
  }
  if (context.profile === 'chaos_team' || context.profile === 'competitive') {
    return {
      id: `objective-pressure-${team.id}-${turn}`,
      kind: 'sabotage',
      description: `Target ${opponentTeam?.name || 'opponent'} leader`,
      priority: 4,
      status: 'active',
      reason: 'Competitive profile is prioritizing opponent disruption.'
    };
  }
  if (context.winCondition === 'netWorth' || context.profile === 'economy_engine') {
    return {
      id: `objective-networth-${team.id}-${turn}`,
      kind: 'netWorth',
      description: 'Build net worth lead',
      priority: 4,
      status: 'active',
      reason: 'Crafting, investments, and efficient selling improve the win metric.'
    };
  }
  return {
    id: `objective-money-${team.id}-${turn}`,
    kind: 'money',
    description: 'Build cash lead',
    priority: opponentLead > 0 ? 5 : 3,
    status: 'active',
    reason: opponentLead > 0 ? 'Opponent is ahead, so immediate cash recovery matters.' : 'Cash lead is the current safest path.'
  };
}

// V6.7 Phase 3a: reverse of mapGoalKindToPlanType, used to mirror an active TeamPlan's objective
// back into team.teamGoals so 2a/2b/2c's existing activeGoal reads (TEAM_ACTION_BANK_GOAL_ACTION_MATCH,
// teamAiActionLendingRequiresCommittedPlan) start reflecting real plan state with zero changes to
// their own code.
const TEAM_PLAN_TYPE_TO_GOAL_KIND: Record<TeamPlanType, TeamGoal['kind']> = {
  resource_chain: 'crafting',
  crafting_chain: 'crafting',
  region_control_push: 'control',
  challenge_push: 'netWorth',
  economic_recovery: 'recovery',
  teammate_support: 'support',
  sabotage_followup: 'sabotage',
  investment_setup: 'netWorth',
  endgame_conversion: 'money',
  block_opponent_win: 'sabotage'
};

// V6.7 Phase 3a: maps a TeamGoal's kind to a persisted TeamPlanType. chooseTeamObjective itself
// stays untouched — this wraps its output into the plan system rather than replacing it. Returns
// null when the goal doesn't warrant a committed multi-step plan (e.g. a simple cash lead with no
// opponent threat is fine as ordinary per-turn decisions, exactly like pre-3a behavior).
function mapGoalKindToPlanType(goal: TeamGoal, context: TeamAiContext): TeamPlanType | null {
  switch (goal.kind) {
    case 'money':
      return (context.opponentLead || 0) > 0 ? 'economic_recovery' : null;
    case 'netWorth':
      return context.craftingOpportunity ? 'crafting_chain' : 'investment_setup';
    case 'regions':
    case 'control':
      return 'region_control_push';
    case 'support':
      return 'teammate_support';
    case 'crafting':
      return 'crafting_chain';
    case 'sabotage':
      return 'sabotage_followup';
    case 'recovery':
      return 'economic_recovery';
    default:
      return null;
  }
}

// V6.7 Phase 3a: builds a TeamPlan's steps for a given plan type. Templates match the 3 worked
// examples from the spec (crafting-chain, region-control-push, sabotage-followup); other plan
// types get a single-step degenerate plan following the same structure so downstream code (step
// lookup, dependency checks, token minting) has no special-case branches. Only AI actors are ever
// assigned a step — a human player is never forced into a scripted plan step.
function buildTeamPlanSteps(
  planType: TeamPlanType,
  goal: TeamGoal,
  aiActorIds: string[],
  context: TeamAiContext
): TeamPlanStep[] {
  if (aiActorIds.length === 0) return [];
  const actorAt = (index: number) => aiActorIds[index % aiActorIds.length];
  const makeStep = (overrides: Partial<TeamPlanStep> & Pick<TeamPlanStep, 'id' | 'order' | 'assignedActorId' | 'actionType'>): TeamPlanStep => ({
    dependsOnStepIds: [],
    requiredCash: 0,
    requiredResources: {},
    status: 'pending',
    overridePermitted: false,
    actionTokenSource: 'normal',
    ...overrides
  });

  switch (planType) {
    case 'crafting_chain':
    case 'resource_chain': {
      const gather = makeStep({ id: 'step-gather', order: 0, assignedActorId: actorAt(0), actionType: 'buy_market', targetKind: 'resource', targetId: goal.targetResource });
      const craft = makeStep({ id: 'step-craft', order: 1, assignedActorId: actorAt(1), actionType: 'craft', dependsOnStepIds: [gather.id] });
      const steps = [gather, craft];
      if (context.winCondition !== 'netWorth') {
        steps.push(makeStep({ id: 'step-sell', order: 2, assignedActorId: actorAt(1), actionType: 'sell', dependsOnStepIds: [craft.id] }));
      }
      return steps;
    }
    case 'region_control_push': {
      const travel = makeStep({ id: 'step-travel', order: 0, assignedActorId: actorAt(0), actionType: 'travel', targetKind: 'region', targetId: goal.targetRegion });
      const deposit = makeStep({ id: 'step-deposit', order: 1, assignedActorId: actorAt(0), actionType: 'region_deposit', targetKind: 'region', targetId: goal.targetRegion, dependsOnStepIds: [travel.id] });
      const steps = [travel, deposit];
      if (aiActorIds.length >= 2) {
        steps.push(makeStep({ id: 'step-reinforce', order: 2, assignedActorId: actorAt(1), actionType: 'region_deposit', targetKind: 'region', targetId: goal.targetRegion, dependsOnStepIds: [deposit.id] }));
      }
      return steps;
    }
    case 'sabotage_followup': {
      const sabotage = makeStep({ id: 'step-sabotage', order: 0, assignedActorId: actorAt(0), actionType: 'sabotage' });
      const followUp = makeStep({ id: 'step-followup', order: 1, assignedActorId: actorAt(1), actionType: 'challenge', dependsOnStepIds: [sabotage.id] });
      return [sabotage, followUp];
    }
    case 'teammate_support':
      return [makeStep({ id: 'step-support', order: 0, assignedActorId: actorAt(0), actionType: 'give_cash' })];
    case 'economic_recovery':
      return [makeStep({ id: 'step-recover', order: 0, assignedActorId: actorAt(0), actionType: 'sell' })];
    case 'investment_setup':
      return [makeStep({ id: 'step-invest', order: 0, assignedActorId: actorAt(0), actionType: 'invest' })];
    case 'endgame_conversion':
      return [makeStep({ id: 'step-convert', order: 0, assignedActorId: actorAt(0), actionType: 'sell' })];
    case 'block_opponent_win':
      return [makeStep({ id: 'step-block', order: 0, assignedActorId: actorAt(0), actionType: 'sabotage' })];
    case 'challenge_push':
      return [makeStep({ id: 'step-challenge', order: 0, assignedActorId: actorAt(0), actionType: 'challenge' })];
    default:
      return [];
  }
}

// V6.7 Phase 3a: generates a persisted TeamPlan, or null if none is warranted this pass. Pure
// function (like chooseTeamObjective) — commitmentRoll is a caller-supplied aiRandom() draw
// (Section 32 determinism: the only RNG source touched anywhere in plan generation), gating
// generation itself so it's probabilistic rather than unconditional.
function generateTeamPlan(
  team: TeamState,
  opponentTeam: TeamState | null,
  context: TeamAiContext,
  commitmentRoll: number
): TeamPlan | null {
  const strength = Math.max(0, Math.min(100, context.settings.teamAiPlanCommitmentStrength));
  if (commitmentRoll > strength / 100) return null;

  const goal = chooseTeamObjective(team, opponentTeam, context);
  const planType = mapGoalKindToPlanType(goal, context);
  if (!planType) return null;

  const aiActorIds = (context.teamActors || []).filter(actor => actor.kind === 'ai').map(actor => actor.id);
  if (aiActorIds.length === 0) return null;

  const steps = buildTeamPlanSteps(planType, goal, aiActorIds, context);
  if (steps.length === 0) return null;

  const day = context.day || 0;
  const reservedResources = steps.reduce<Record<string, number>>((acc, step) => {
    for (const [resource, qty] of Object.entries(step.requiredResources)) {
      acc[resource] = (acc[resource] || 0) + qty;
    }
    return acc;
  }, {});
  const reservedCash = steps.reduce((sum, step) => sum + step.requiredCash, 0);
  // Heuristic expected value: proportional to the objective's priority and step count, scaled
  // down when the team is already behind (a behind team's plans should be evaluated more
  // cautiously against alternatives) — this reuses only signals chooseTeamObjective/context
  // already expose, not a from-scratch scoring model.
  const expectedValue = goal.priority * 100 * steps.length * ((context.opponentLead || 0) > 0 ? 0.85 : 1);
  const sensitivity = Math.max(0, Math.min(100, context.settings.teamAiPlanInterruptionSensitivity));
  const interruptionThreshold = Math.max(0, expectedValue * (1 - sensitivity / 100));
  const expiresDay = day + Math.min(context.settings.teamAiPlanMaximumDurationDays, steps.length * 2);

  return {
    id: `team_plan_${team.id}_${day}_${Math.random().toString(36).slice(2, 8)}`,
    type: planType,
    teamId: team.id,
    objective: goal.description,
    priority: goal.priority,
    status: 'active',
    createdDay: day,
    expiresDay,
    assignedActorIds: Array.from(new Set(steps.map(step => step.assignedActorId))),
    steps,
    reservedCash,
    reservedResources,
    expectedValue,
    interruptionThreshold
  };
}

// V6.7 Phase 3a: checks an active plan's continuation status. Priority order — first match wins,
// never combines reasons (the spec's closed 7-value TeamPlanInterruptionReason union and its
// "minor score differences should not constantly replace active plans" safeguard both depend on
// this). liquidityDangerActorIds and candidatePlan are precomputed by the caller (analyzeTeamLiquidity
// and a speculative generateTeamPlan call are both hooks, so this function stays pure/testable).
function evaluateTeamPlanContinuation(
  plan: TeamPlan,
  team: TeamState,
  context: TeamAiContext,
  liquidityDangerActorIds: string[],
  candidatePlan: TeamPlan | null
): { action: 'continue' | 'complete' | 'interrupt' | 'reevaluate'; reason?: TeamPlanInterruptionReason } {
  const day = context.day || 0;

  if (plan.steps.every(step => step.status === 'done' || step.status === 'skipped')) {
    return { action: 'complete' };
  }

  // Stalled-plan heuristic for "expected value collapsed": no progress made past the halfway
  // point of the plan's allotted duration is treated as the value no longer being realizable.
  const stepsDone = plan.steps.filter(step => step.status === 'done').length;
  const halfLifeDay = plan.createdDay + Math.max(1, Math.round((plan.expiresDay - plan.createdDay) / 2));
  if (stepsDone === 0 && day > halfLifeDay) {
    return { action: 'interrupt', reason: 'expected_value_collapsed' };
  }

  const opponentLead = context.opponentLead || 0;
  const nearEndgame = context.totalDays > 0 && day >= context.totalDays * 0.8;
  if (nearEndgame && opponentLead > (context.teamScore?.total || 0) * 0.5 && opponentLead > 0) {
    return { action: 'interrupt', reason: 'opponent_immediate_win_threat' };
  }

  if (plan.assignedActorIds.some(actorId => liquidityDangerActorIds.includes(actorId))) {
    return { action: 'interrupt', reason: 'actor_financial_danger' };
  }

  if (plan.assignedActorIds.some(actorId => !team.actorIds.includes(actorId))) {
    return { action: 'interrupt', reason: 'completion_impossible' };
  }

  if (day > plan.expiresDay) {
    return { action: 'interrupt', reason: 'completion_impossible' };
  }

  const sensitivity = Math.max(0, Math.min(100, context.settings.teamAiPlanInterruptionSensitivity));
  if (candidatePlan && candidatePlan.expectedValue >= plan.expectedValue * (1 + (sensitivity / 100) * 0.5)) {
    return { action: 'interrupt', reason: 'stronger_opportunity' };
  }

  const reevaluationFrequency = Math.max(1, context.settings.teamAiPlanReevaluationFrequency);
  if (day % reevaluationFrequency === 0) {
    return { action: 'reevaluate' };
  }

  return { action: 'continue' };
}

// Team AI Overseer System Phase O5: maps a TeamGoal's kind to the categories of action a
// Strategic Command directive addressing that goal should permit — same lookup-table style as
// TEAM_PLAN_TYPE_TO_GOAL_KIND/mapGoalKindToPlanType above, not a new abstraction.
const mapGoalKindToAllowedActionCategories = (kind: TeamGoal['kind']): TeamModeActionCategory[] => {
  switch (kind) {
    case 'control':
    case 'regions':
      return ['region_deposit', 'travel'];
    case 'support':
      return ['support'];
    case 'sabotage':
      return ['sabotage'];
    case 'netWorth':
      return ['craft', 'invest', 'sell'];
    case 'crafting':
      return ['craft', 'buy_market'];
    case 'recovery':
      return ['support', 'challenge', 'sell'];
    case 'money':
    default:
      return ['sell', 'craft', 'buy_market'];
  }
};

// Team AI Overseer System Phase O7 (GD4): picks the single most profitable recipe (reusing the
// exact profit comparison already used elsewhere: sell value vs. ingredient cost) and lists which
// of its ingredients the actor is currently short on — display-only, no new profitability formula,
// no new acquisition mechanic (existing market-purchase/crafting scoring already handles that).
const computeDirectiveRequiredResources = (actor: { inventory?: string[] }): string[] => {
  const inventory = actor.inventory || [];
  let bestRecipe: (typeof CRAFTING_RECIPES)[number] | null = null;
  let bestProfit = -Infinity;
  for (const recipe of CRAFTING_RECIPES) {
    const ingredientCost = Object.entries(recipe.inputs).reduce(
      (sum, [resource, count]) => sum + getResourceMarketPrice(resource) * Number(count), 0
    );
    const sellValue = recipe.baseValue || getResourceMarketPrice(recipe.output);
    const profit = sellValue - ingredientCost;
    if (profit > bestProfit) {
      bestProfit = profit;
      bestRecipe = recipe;
    }
  }
  if (!bestRecipe) return [];
  return Object.entries(bestRecipe.inputs)
    .filter(([resource, count]) => inventory.filter(item => item === resource).length < Number(count))
    .map(([resource]) => resource);
};

// Team AI Overseer System Phase O5: builds one TeamDirective for a single AI actor from the
// team's already-chosen objective (chooseTeamObjective, reused verbatim by the caller — not
// re-derived per actor). Shadow/Advisory display only this phase originally; Phase O7 made
// maxSpending/requiredResources real (see below) — treasuryAllocation is still populated at
// creation time as 0 and only ever set by the O7 directive-scoped funding-request trigger
// inside performTeamAiTurn, since it depends on a live shortfall check, not just the goal.
// successCondition/failureCondition are still plain display strings, not yet evaluated against
// real outcomes (a future phase gives them a real trigger once directives are observably tied to
// completion/failure).
function generateTeamDirective(
  actor: ActorState,
  team: TeamState,
  goal: TeamGoal,
  context: TeamAiContext,
  day: number,
  turn: number
): TeamDirective {
  const endgameActive = isEndgamePeriod(day, context.totalDays, context.settings.teamAiEndgameStartPercent);
  const horizon: TeamDirective['horizon'] = endgameActive
    ? 'endgame'
    : (actor.inEconomicRecovery || goal.kind === 'recovery')
      ? 'immediate'
      : 'short_term';
  const expiresDay = horizon === 'immediate'
    ? day + 1
    : horizon === 'endgame'
      ? day + Math.max(1, context.totalDays - day)
      : day + Math.max(1, context.settings.teamAiStrategicCommandDirectiveDurationDays);
  // Team AI Overseer System Phase O7 (GD1): a real spending cap, computed once at creation time
  // from the actor's current spendable cash — reused verbatim, never re-derived, at the O6 bias
  // site in getRankedTeamAiDecisions as an additional filter on the scoring bonus.
  const vaultActive = context.settings.teamCompetitiveAiEnabled && context.settings.teamCashVaultEnabled;
  const maxSpending = Math.round(getActorSpendableCash(actor, vaultActive) * (context.settings.teamAiStrategicCommandMaxSpendingPercent / 100));
  // Team AI Overseer System Phase O7 (GD4): crafting-oriented directives list genuinely-missing
  // ingredients for the actor's best-available recipe (reusing CRAFTING_RECIPES/inventory checks
  // already used elsewhere) — display-only; acquisition is already handled by the existing
  // market-purchase/crafting decision scoring, never a new fulfillment mechanic.
  const requiredResources = goal.kind === 'crafting' ? computeDirectiveRequiredResources(actor) : [];
  return {
    id: `directive_${team.id}_${actor.id}_${day}_${Math.random().toString(36).slice(2, 8)}`,
    teamId: team.id,
    assignedActorId: actor.id,
    objective: goal.description,
    horizon,
    priority: goal.priority,
    createdDay: day,
    createdTurn: turn,
    expiresDay,
    maxSpending,
    treasuryAllocation: 0,
    requiredResources,
    allowedActionCategories: mapGoalKindToAllowedActionCategories(goal.kind),
    successCondition: `Team's ${context.winCondition} metric improves before this directive expires.`,
    failureCondition: 'Directive expires with no measurable progress.',
    retryLimit: 1,
    retryCount: 0,
    fallback: 'reassess next cycle',
    reassignmentPermitted: true,
    status: 'proposed'
  };
}

// Team AI Overseer System Phase O5: deliberately minimal lifecycle this phase — a directive only
// ever expires on its own schedule. Real completion/failure detection tied to observed actor
// behavior is Phase O6+'s job, once directives can actually be seen influencing decisions.
function evaluateTeamDirectiveContinuation(directive: TeamDirective, currentDay: number): 'continue' | 'expire' {
  return currentDay >= directive.expiresDay ? 'expire' : 'continue';
}

