const clampTeammatePerformanceImpact = (impact: number) => {
  return Math.max(-1, Math.min(1, impact));
};

const normalizeWinMetric = (metric: unknown, fallback: WinMetric = 'money'): WinMetric => {
  if (metric === 'netWorth' || metric === 'regions') return metric;
  if (metric === 'money') return metric;
  return fallback;
};

const sanitizeWinMetricTieBreakers = (value: unknown): WinMetric[] => {
  const source = Array.isArray(value) ? value : DEFAULT_WIN_CONDITION_TIEBREAKERS;
  const unique = source
    .map(metric => normalizeWinMetric(metric, 'netWorth'))
    .filter((metric, index, items) => items.indexOf(metric) === index);
  WIN_METRIC_OPTIONS.forEach(metric => {
    if (!unique.includes(metric)) {
      unique.push(metric);
    }
  });
  return unique.slice(0, WIN_METRIC_OPTIONS.length);
};

const getWinMetricLowCashThreshold = (metric: WinMetric) => {
  switch (metric) {
    case 'regions':
      return 900;
    case 'netWorth':
      return 725;
    case 'money':
    default:
      return 650;
  }
};

const describeWinConditionBehavior = (metric: WinMetric, decisionType?: string) => {
  switch (metric) {
    case 'regions':
      if (decisionType === 'region_deposit' || decisionType === 'travel' || decisionType === 'cashout_region') {
        return 'Region majority pressure changed this ranking.';
      }
      return 'Region control, denial, and defense are weighted more heavily.';
    case 'netWorth':
      if (['invest', 'craft', 'buy_market', 'buy_equipment'].includes(String(decisionType || ''))) {
        return 'Asset growth and value retention raised this action.';
      }
      return 'Total net worth growth and value preservation shaped this decision.';
    case 'money':
    default:
      if (['sell', 'challenge', 'cashout_region'].includes(String(decisionType || ''))) {
        return 'Immediate cash conversion improved this action.';
      }
      return 'Short-horizon cash gain and liquidity shaped this decision.';
  }
};

const formatPercentShareValue = (value: number, total: number) => {
  if (total <= 0 || value <= 0) return '0%';
  return `${Math.round((value / total) * 100)}%`;
};

const normalizeDirectiveStrength = (strength: unknown): DirectiveStrength => {
  if (strength === 'low' || strength === 'high' || strength === 'priority') return strength;
  return 'standard';
};

const formatDirectiveStrengthLabel = (strength: DirectiveStrength | string | null | undefined) => {
  return DIRECTIVE_STRENGTH_LABELS[normalizeDirectiveStrength(strength)];
};

const getDirectiveStrengthProfile = (strength: DirectiveStrength | string | null | undefined) => {
  return DIRECTIVE_STRENGTH_PROFILES[normalizeDirectiveStrength(strength)];
};

const getEffectiveDirectiveStrengthProfile = (
  strength: DirectiveStrength | string | null | undefined,
  options?: { teamMode?: boolean }
) => {
  const normalized = normalizeDirectiveStrength(strength);
  return options?.teamMode ? TEAM_DIRECTIVE_STRENGTH_PROFILES[normalized] : DIRECTIVE_STRENGTH_PROFILES[normalized];
};

const formatAiRoleModeLabel = (mode: AiRoleMode | string | null | undefined) => {
  switch (normalizeAiRoleMode(mode)) {
    case 'money_focus':
      return 'Money Focus';
    case 'support_focus':
      return 'Support Focus';
    case 'control_focus':
      return 'Control Focus';
    case 'recovery':
      return 'Recovery';
    case 'normal':
    default:
      return 'Normal';
  }
};

const formatLiquidityStateLabel = (state: TeamLiquidityState | string | null | undefined) => {
  switch (state) {
    case 'BROKE':
      return 'Broke';
    case 'UNDERFUNDED':
      return 'Underfunded';
    case 'RICH':
      return 'Rich';
    case 'CARRYING':
      return 'Carrying';
    case 'HEALTHY':
    default:
      return 'Healthy';
  }
};

const buildSupportPairKey = (fromActorId: string, toActorId: string) => `${fromActorId}->${toActorId}`;

const getTeamDirectiveDisplayLabel = (
  type: TeamMessageType | string,
  payload?: TeamMessagePayload | null
) => {
  const note = String(payload?.note || '').trim().toLowerCase();
  if (type === 'follow_my_lead' && note.includes('focus on money')) {
    return 'focus on money';
  }
  if (type === 'request_cover' && note.includes('help control this region')) {
    return 'help control this region';
  }
  if (type === 'reserve_region' && note.includes('avoid my target')) {
    return 'avoid my target';
  }
  if ((type === 'focus_resource' || type === 'gather_resource') && note.includes('gather this resource')) {
    return 'gather this resource';
  }
  if (type === 'combo_setup' && note.includes('set up a combo')) {
    return 'set up a combo';
  }
  return String(type).replace(/_/g, ' ');
};

const getDirectiveStrengthSortValue = (strength: DirectiveStrength | string | null | undefined) => {
  return DIRECTIVE_STRENGTH_ORDER[normalizeDirectiveStrength(strength)];
};

const getDirectiveStrengthBadgeClasses = (
  themeStyles: Record<string, string>,
  strength: DirectiveStrength | string | null | undefined
) => {
  const normalized = normalizeDirectiveStrength(strength);
  const baseClasses = 'inline-flex items-center rounded-full border px-2 py-0.5 text-[11px] font-semibold';
  if (normalized === 'priority') {
    return `${baseClasses} ${themeStyles.badgeWarning} ${themeStyles.warningBorder}`;
  }
  if (normalized === 'high') {
    return `${baseClasses} ${themeStyles.badgeSuccess} ${themeStyles.successBorder}`;
  }
  return `${baseClasses} ${themeStyles.badgePrimary} ${themeStyles.borderLight}`;
};

const sortTeamMessagesByDirectiveStrength = (messages: TeamMessage[]) => {
  return [...(messages || [])].sort((left, right) => {
    const strengthDelta = getDirectiveStrengthSortValue(right.strength) - getDirectiveStrengthSortValue(left.strength);
    if (strengthDelta !== 0) return strengthDelta;
    if (right.priority !== left.priority) return right.priority - left.priority;
    return right.createdTurn - left.createdTurn;
  });
};

const createDefaultRecentPerformanceByActor = (actorIds: string[]) => {
  return actorIds.reduce<Record<string, TeammatePerformanceSample[]>>((acc, actorId) => {
    acc[actorId] = [];
    return acc;
  }, {});
};

const sanitizeTeammatePerformanceSamples = (samples: unknown): TeammatePerformanceSample[] => {
  if (!Array.isArray(samples)) return [];
  return samples
    .map(sample => {
      if (!sample || typeof sample !== 'object') return null;
      const actionType = (sample as TeammatePerformanceSample).actionType;
      if (!['challenge', 'craft', 'economy', 'support', 'control'].includes(actionType)) {
        return null;
      }
      return {
        turn: typeof (sample as TeammatePerformanceSample).turn === 'number' && isFinite((sample as TeammatePerformanceSample).turn)
          ? Math.floor((sample as TeammatePerformanceSample).turn)
          : 0,
        actionType,
        impact: clampTeammatePerformanceImpact(
          typeof (sample as TeammatePerformanceSample).impact === 'number' && isFinite((sample as TeammatePerformanceSample).impact)
            ? (sample as TeammatePerformanceSample).impact
            : 0
        )
      } as TeammatePerformanceSample;
    })
    .filter((sample): sample is TeammatePerformanceSample => Boolean(sample))
    .slice(-TEAMMATE_PERFORMANCE_SYNC_WINDOW);
};

const computeRecentActorPerformance = (samples: TeammatePerformanceSample[]) => {
  const recentSamples = (Array.isArray(samples) ? samples : [])
    .slice(-TEAMMATE_PERFORMANCE_SYNC_WINDOW)
    .reverse();
  if (recentSamples.length === 0) return 0;

  let weightedImpact = 0;
  let totalWeight = 0;

  recentSamples.forEach((sample, index) => {
    const weight = TEAMMATE_PERFORMANCE_SYNC_WEIGHTS[index] || TEAMMATE_PERFORMANCE_SYNC_WEIGHTS[TEAMMATE_PERFORMANCE_SYNC_WEIGHTS.length - 1];
    weightedImpact += clampTeammatePerformanceImpact(sample.impact) * weight;
    totalWeight += weight;
  });

  const normalized = totalWeight > 0 ? (weightedImpact / totalWeight) : 0;
  return Math.max(-TEAMMATE_PERFORMANCE_SYNC_MAX, Math.min(TEAMMATE_PERFORMANCE_SYNC_MAX, normalized * TEAMMATE_PERFORMANCE_SYNC_MAX));
};

// V6.8 Phase D: Teammate Performance Sync 2.0 — realized-value tracking constants/helpers, kept
// as plain module-level pure functions (not hooks) so they're callable from anywhere in the file
// regardless of declaration order, following the exact TDZ-avoidance pattern V6.8 Phase C
// established for its own module-level helpers.
const SYNC2_REALIZED_VALUE_WINDOW = 8;
const SYNC2_RECENCY_WEIGHTS = [1, 0.88, 0.78, 0.68, 0.6, 0.52, 0.46, 0.4];
// V6.8 Phase D: Guaranteed Recovery Protocol Tier 2's fixed teammate-support transfer size.
const GUARANTEED_RECOVERY_TEAMMATE_TRANSFER_AMOUNT = 500;

const createDefaultRealizedPerformanceByActor = (actorIds: string[]) => {
  return actorIds.reduce<Record<string, RealizedValueSample[]>>((acc, actorId) => {
    acc[actorId] = [];
    return acc;
  }, {});
};

const sanitizeRealizedValueSamples = (samples: unknown): RealizedValueSample[] => {
  if (!Array.isArray(samples)) return [];
  return samples
    .map(sample => {
      if (!sample || typeof sample !== 'object') return null;
      const category = (sample as RealizedValueSample).category;
      if (!['challenge', 'craft', 'economy', 'support', 'control'].includes(category)) {
        return null;
      }
      return {
        turn: typeof (sample as RealizedValueSample).turn === 'number' && isFinite((sample as RealizedValueSample).turn)
          ? Math.floor((sample as RealizedValueSample).turn)
          : 0,
        category,
        netWorthDelta: typeof (sample as RealizedValueSample).netWorthDelta === 'number' && isFinite((sample as RealizedValueSample).netWorthDelta)
          ? (sample as RealizedValueSample).netWorthDelta
          : 0
      } as RealizedValueSample;
    })
    .filter((sample): sample is RealizedValueSample => Boolean(sample))
    .slice(-SYNC2_REALIZED_VALUE_WINDOW);
};

const computeRecentRealizedPerformance = (samples: RealizedValueSample[], referenceScale: number): number => {
  const recentSamples = (Array.isArray(samples) ? samples : [])
    .slice(-SYNC2_REALIZED_VALUE_WINDOW)
    .reverse();
  if (recentSamples.length === 0) return 0;

  const scale = Math.max(100, (isFinite(referenceScale) ? referenceScale : 0) * 0.15);
  let weightedDelta = 0;
  let totalWeight = 0;
  recentSamples.forEach((sample, index) => {
    const weight = SYNC2_RECENCY_WEIGHTS[index] || SYNC2_RECENCY_WEIGHTS[SYNC2_RECENCY_WEIGHTS.length - 1];
    weightedDelta += (sample.netWorthDelta / scale) * weight;
    totalWeight += weight;
  });

  const normalized = totalWeight > 0 ? (weightedDelta / totalWeight) : 0;
  return Math.max(-1, Math.min(1, normalized));
};

// V6.8 Phase D: strategy learning — a bounded, per-actor, per-category "what's-been-working-for-
// me" bias, computed only from the actor's OWN realized-value samples (never the teammate's).
const computeCategoryStrategyLearningBias = (
  ownSamples: RealizedValueSample[],
  category: TeammatePerformanceActionType,
  referenceScale: number
): number => {
  const matching = (Array.isArray(ownSamples) ? ownSamples : []).filter(sample => sample.category === category);
  if (matching.length === 0) return 0;
  const scale = Math.max(100, (isFinite(referenceScale) ? referenceScale : 0) * 0.15);
  const averageDelta = matching.reduce((sum, sample) => sum + sample.netWorthDelta, 0) / matching.length;
  return Math.max(-1, Math.min(1, averageDelta / scale));
};

// V6.8 Phase D: maps an AI decision type onto Sync 1.0's exact 5-category taxonomy, reused here so
// realized-value samples/strategy-learning buckets stay directly comparable to Sync 1.0's own
// per-decision-type scoring table.
const mapAiActionTypeToPerformanceCategory = (actionType: AIAction['type']): TeammatePerformanceActionType => {
  if (actionType === 'challenge') return 'challenge';
  if (actionType === 'craft') return 'craft';
  if (actionType === 'give_cash' || actionType === 'give_resource') return 'support';
  if (actionType === 'sabotage' || actionType === 'region_deposit' || actionType === 'travel' || actionType === 'special_ability') return 'control';
  return 'economy';
};

// V6.8 Phase D: category-specific challenge expertise bonus, additive into
// calculateActorChallengeSuccessChance's existing bonusChance parameter — composes with, never
// replaces, the Team Initiative "challenge assist" bonus. Diminishing returns, capped by setting.
const getChallengeCategoryExpertiseBonus = (
  actor: { challengeCategoryExpertise?: Record<string, number> },
  challengeType: string,
  settings: GameSettingsState
): number => {
  if (!settings.teammatePerformanceSync2Enabled || !settings.teammatePerformanceSync2ChallengeExpertiseEnabled) return 0;
  const wins = actor.challengeCategoryExpertise?.[challengeType] || 0;
  return Math.min(settings.teammatePerformanceSync2ChallengeExpertiseMaxBonus, wins * 0.01);
};

const formatTeammatePerformanceSyncLabel = (modifier: number) => {
  const percent = Math.round(modifier * 100);
  if (modifier >= TEAMMATE_PERFORMANCE_SYNC_STATUS_THRESHOLD) {
    return `Sync: Boosted (+${percent}%)`;
  }
  if (modifier <= -TEAMMATE_PERFORMANCE_SYNC_STATUS_THRESHOLD) {
    return `Sync: Stabilized (${percent}%)`;
  }
  return 'Sync: Stable';
};

const formatTeammatePerformanceSyncMode = (modifier: number) => {
  if (modifier >= TEAMMATE_PERFORMANCE_SYNC_STATUS_THRESHOLD) return 'Boosted';
  if (modifier <= -TEAMMATE_PERFORMANCE_SYNC_STATUS_THRESHOLD) return 'Stabilized';
  return 'Stable';
};

