const getAiStrategyLabWeightRange = (
  settings: Pick<GameSettingsState, 'aiStrategyLabSafeRangesEnabled' | 'aiStrategyLabExtremeModeEnabled'> | Partial<GameSettingsState>
) => {
  if (settings.aiStrategyLabSafeRangesEnabled === false) {
    return { min: 0, max: 5 };
  }

  if (settings.aiStrategyLabExtremeModeEnabled) {
    return { min: 0, max: 3 };
  }

  return { min: 0.5, max: 1.75 };
};

const sanitizeAiEvaluationFactorsV63 = (
  value: unknown,
  settings: Pick<GameSettingsState, 'aiStrategyLabSafeRangesEnabled' | 'aiStrategyLabExtremeModeEnabled'> | Partial<GameSettingsState>
): AiEvaluationFactorSetting[] => {
  const range = getAiStrategyLabWeightRange(settings);
  const savedById = Array.isArray(value)
    ? value.reduce<Record<string, Partial<AiEvaluationFactorSetting>>>((acc, entry) => {
        if (entry && typeof entry === 'object' && typeof (entry as Partial<AiEvaluationFactorSetting>).id === 'string') {
          acc[String((entry as Partial<AiEvaluationFactorSetting>).id)] = entry as Partial<AiEvaluationFactorSetting>;
        }
        return acc;
      }, {})
    : {};

  return DEFAULT_AI_EVALUATION_FACTORS_V63.map(defaultFactor => {
    const savedFactor = savedById[defaultFactor.id];
    return {
      ...defaultFactor,
      appliesTo: [...defaultFactor.appliesTo],
      enabled: typeof savedFactor?.enabled === 'boolean' ? savedFactor.enabled : defaultFactor.enabled,
      weight: clampSettingNumber(savedFactor?.weight, defaultFactor.weight, range.min, range.max)
    };
  });
};

const getAiStrategyLabModeKind = (
  selectedMode: GameModeSelection | null
): AiStrategyLabModeKind | null => {
  if (selectedMode === 'ai') return 'standard';

  if (
    selectedMode === 'team_human_ai_vs_ai_ai' ||
    selectedMode === 'team_ai_vs_ai'
  ) {
    return 'team';
  }

  return null;
};

const shouldUseAiStrategyLabForMode = (
  selectedMode: GameModeSelection | null,
  settings: GameSettingsState
) => {
  if (!settings.aiStrategyLabEnabled) return false;

  const isStandardAi = selectedMode === 'ai';
  const isTeamMode =
    selectedMode === 'team_human_ai_vs_ai_ai' ||
    selectedMode === 'team_ai_vs_ai';

  if (settings.aiStrategyLabScope === 'standard_only') return isStandardAi;
  if (settings.aiStrategyLabScope === 'team_only') return isTeamMode;

  return isStandardAi || isTeamMode;
};

const getAiStrategyPresetForActorV63 = (
  relationshipLabel: ActorRelationshipLabel,
  settings: GameSettingsState
): AiStrategyLabPreset => {
  if (!settings.aiStrategyLabSeparateProfilesEnabled) {
    return settings.aiStrategyLabPreset;
  }

  if (relationshipLabel === 'your_teammate' || relationshipLabel === 'ai_team_teammate') {
    return settings.playerTeammateAiPreset;
  }

  if (
    relationshipLabel === 'your_opponent' ||
    relationshipLabel === 'ai_team_opponent'
  ) {
    return settings.opponentAiPreset;
  }

  return settings.aiStrategyLabPreset;
};

const applyAiStrategyLabPresetV63 = (
  factors: AiEvaluationFactorSetting[],
  preset: AiStrategyLabPreset,
  settings: GameSettingsState
): AiEvaluationFactorSetting[] => {
  const presetWeights = AI_STRATEGY_LAB_PRESETS_V63[preset] || AI_STRATEGY_LAB_PRESETS_V63.classic;
  const range = getAiStrategyLabWeightRange(settings);

  return factors.map(factor => {
    const nextWeight = presetWeights[factor.id] ?? factor.weight;

    return {
      ...factor,
      appliesTo: [...factor.appliesTo],
      weight: Math.max(range.min, Math.min(range.max, nextWeight))
    };
  });
};

const getAiStrategyLabScorePreviewV63 = (
  beforeDecisions: Array<AIAction & { score: number }>,
  afterDecisions: Array<AIAction & { score: number }>,
  settings: GameSettingsState
): AiStrategyLabScorePreview | null => {
  if (!settings.aiStrategyLabScorePreviewEnabled) return null;

  const simplify = (decision: AIAction & { score: number }) => ({
    action: decision.description || decision.type,
    score: Math.round(Number(decision.score) || 0)
  });

  return {
    before: beforeDecisions
      .slice()
      .sort((a, b) => b.score - a.score)
      .slice(0, 3)
      .map(simplify),

    after: afterDecisions
      .slice()
      .sort((a, b) => b.score - a.score)
      .slice(0, 3)
      .map(simplify)
  };
};

const getAiStrategyLabWarningsV63 = (
  factors: AiEvaluationFactorSetting[],
  settings: GameSettingsState
): string[] => {
  if (!settings.aiStrategyLabWarningsEnabled) return [];

  const getWeight = (id: AiEvaluationFactorId) =>
    factors.find(factor => factor.id === id && factor.enabled)?.weight ?? 1;

  const warnings: string[] = [];

  const travel = getWeight('travel');
  const cashSafety = getWeight('cash_safety');
  const sabotage = getWeight('sabotage');
  const profit = getWeight('profit');
  const risk = getWeight('risk');
  const comeback = getWeight('comeback');
  const support = getWeight('support');
  const sharedCash = getWeight('shared_cash');

  if (travel > 1.4 && cashSafety < 0.8) {
    warnings.push('High Travel + Low Cash Safety may make AI waste money moving too often.');
  }

  if (sabotage > 1.4 && profit < 0.8) {
    warnings.push('High Sabotage + Low Profit may make AI annoying but less competitive.');
  }

  if (risk < 0.7 && comeback > 1.4) {
    warnings.push('Low Risk Penalty + High Comeback may make losing AI play too recklessly.');
  }

  if (support > 1.4 && sharedCash < 0.8) {
    warnings.push('High Support + Low Shared Cash may make teammates give away too much money.');
  }

  return warnings;
};

const getAiStrategyLabImpactPreviewV63 = (
  factors: AiEvaluationFactorSetting[],
  modeKind: AiStrategyLabModeKind
): string[] => {
  const messages: string[] = [];

  const factor = (id: AiEvaluationFactorId) =>
    factors.find(item =>
      item.id === id &&
      item.enabled &&
      item.appliesTo.includes(modeKind)
    );

  const profit = factor('profit');
  if (profit && profit.weight > 1.2) {
    messages.push('AI will prioritize making money faster.');
  }

  const risk = factor('risk');
  if (risk && risk.weight < 0.8) {
    messages.push('AI will take more risks and attempt harder challenges.');
  }
  if (risk && risk.weight > 1.2) {
    messages.push('AI will play safer and avoid risky moves.');
  }

  const travel = factor('travel');
  if (travel && travel.weight > 1.2) {
    messages.push('AI will travel more often to chase better opportunities.');
  }
  if (travel && travel.weight < 0.8) {
    messages.push('AI will travel less and save cash.');
  }

  const support = factor('support');
  if (modeKind === 'team' && support && support.weight > 1.2) {
    messages.push('AI teammates will support each other more often.');
  }

  const coordination = factor('coordination');
  if (modeKind === 'team' && coordination && coordination.weight > 1.2) {
    messages.push('Team AI will follow shared team strategy more strongly.');
  }

  const sabotage = factor('sabotage');
  if (sabotage && sabotage.weight > 1.2) {
    messages.push('AI will sabotage opponents more aggressively.');
  }

  const comeback = factor('comeback');
  if (comeback && comeback.weight > 1.2) {
    messages.push('AI will become more aggressive when losing.');
  }

  if (messages.length === 0) {
    messages.push('AI behavior will stay close to Classic V6.2 logic.');
  }

  return messages;
};

const inferTeamStrategyModeV63 = (
  actor: ActorState,
  options: {
    assignedRole?: TeamAiRole;
    teamBehind: boolean;
    teamAhead: boolean;
    actorLowCash: boolean;
    teamNeedsCash: boolean;
    teammateNeedsHelp: boolean;
    winCondition: WinMetric;
  }
): TeamStrategyModeV63 => {
  if (options.actorLowCash || options.teamNeedsCash) return 'recovery';
  if (options.teammateNeedsHelp || options.assignedRole === 'support') return 'support';
  if (options.assignedRole === 'crafter') return 'resource';
  if (options.assignedRole === 'controller' || options.winCondition === 'regions') return 'control';
  if (options.assignedRole === 'saboteur') return options.teamBehind ? 'attack' : 'defense';
  if (options.teamBehind) return 'attack';
  if (options.teamAhead) return 'defense';
  if (options.winCondition === 'money' || options.winCondition === 'netWorth') return 'earn';

  return 'earn';
};

const inferAiPersonalityForTeamBrainV63 = (
  role: TeamAiRole | undefined,
  settings: GameSettingsState
): AiPersonalityV63 => {
  if (!settings.teamBrainPersonalitiesEnabled) return 'balanced';

  switch (role) {
    case 'support':
      return 'support_teammate';
    case 'saboteur':
      return 'saboteur';
    case 'crafter':
      return 'resource_trader';
    case 'controller':
      return 'aggressive';
    case 'recovery':
      return 'saver';
    case 'earner':
      return 'balanced';
    case 'explorer':
      return 'balanced';
    default:
      return 'balanced';
  }
};

const buildTeamBrainContextV63 = (
  actor: ActorState,
  options: {
    assignedRole?: TeamAiRole;
    teamBehind: boolean;
    teamAhead: boolean;
    teamNeedsCash: boolean;
    teammateNeedsHelp: boolean;
    opponentIsAhead: boolean;
    settings: GameSettingsState;
    winCondition: WinMetric;
  }
): TeamBrainContextV63 => {
  const actorLowCash = actor.money < 500;
  const veryLowCash = actor.money < 300;

  const teamStrategyMode = options.settings.teamBrainStrategyModesEnabled
    ? inferTeamStrategyModeV63(actor, {
        assignedRole: options.assignedRole,
        teamBehind: options.teamBehind,
        teamAhead: options.teamAhead,
        actorLowCash,
        teamNeedsCash: options.teamNeedsCash,
        teammateNeedsHelp: options.teammateNeedsHelp,
        winCondition: options.winCondition
      })
    : 'earn';

  const actorPersonality = inferAiPersonalityForTeamBrainV63(
    options.assignedRole,
    options.settings
  );

  return {
    actor,
    actorRole: options.assignedRole,
    actorPersonality,
    teamStrategyMode,
    teamBehind: options.teamBehind,
    teamAhead: options.teamAhead,
    teamNeedsCash: options.teamNeedsCash,
    teamNeedsSupport: options.teammateNeedsHelp,
    teammateNeedsHelp: options.teammateNeedsHelp,
    opponentIsAhead: options.opponentIsAhead,
    cashPressure: veryLowCash ? 1 : actorLowCash ? 0.6 : 0,
    comebackPressure: options.teamBehind ? 1 : 0,
    defensePressure: options.teamAhead ? 1 : 0,
    supportPressure: options.teammateNeedsHelp ? 1 : 0
  };
};

const getDecisionSuccessChanceV63 = (decision: AIAction & { score: number }) => {
  const rawChance =
    decision.data?.successChance ??
    decision.data?.teamModeMeta?.successChance ??
    decision.plan?.confidence ??
    0.5;

  return Math.max(0, Math.min(1, Number(rawChance) || 0.5));
};

const getDecisionCashCostV63 = (decision: AIAction & { score: number }) => {
  const rawCost =
    decision.data?.cost ??
    decision.data?.amount ??
    decision.data?.wager ??
    decision.data?.price ??
    decision.data?.totalCost ??
    0;

  return Math.max(0, Number(rawCost) || 0);
};

const isResourceCloseToHighValueCraftV63 = (
  actor: ActorState,
  resource: unknown
) => {
  if (typeof resource !== 'string' || !resource) return false;

  const inventoryCounts = (actor.inventory || []).reduce<Record<string, number>>((acc, item) => {
    acc[item] = (acc[item] || 0) + 1;
    return acc;
  }, {});

  return CRAFTING_RECIPES.some(recipe => {
    const requiredCount = Number(recipe.inputs?.[resource]) || 0;
    if (requiredCount <= 0) return false;

    const outputValue = getResourceMarketPrice(recipe.output) || 0;
    const inputValue = Object.entries(recipe.inputs).reduce((sum, [input, required]) => (
      sum + ((getResourceMarketPrice(input) || 0) * (Number(required) || 0))
    ), 0);
    const highValueCraft = outputValue >= Math.max(500, inputValue * 1.2);
    if (!highValueCraft) return false;

    const missingNow = Object.entries(recipe.inputs).reduce((missing, [input, required]) => (
      missing + Math.max(0, (Number(required) || 0) - (inventoryCounts[input] || 0))
    ), 0);
    const countsAfterSale = {
      ...inventoryCounts,
      [resource]: Math.max(0, (inventoryCounts[resource] || 0) - 1)
    };
    const missingAfterSale = Object.entries(recipe.inputs).reduce((missing, [input, required]) => (
      missing + Math.max(0, (Number(required) || 0) - (countsAfterSale[input] || 0))
    ), 0);

    return missingNow <= 1 && missingAfterSale > missingNow;
  });
};

const appendDecisionScoreStageV63 = <T extends AIAction & { score: number }>(
  decision: T,
  stage: DecisionScoreStage,
  reasons: string[] = [],
  includeVerboseReasons = true
): T => {
  const existingReasons = Array.isArray(decision.traceMeta?.reasons)
    ? decision.traceMeta.reasons
    : [];
  const existingStages = Array.isArray(decision.traceMeta?.scoreStages)
    ? decision.traceMeta.scoreStages
    : [];
  const nextReasons = includeVerboseReasons
    ? Array.from(new Set([...existingReasons, ...reasons])).slice(0, 10)
    : existingReasons.slice(0, 10);

  return {
    ...decision,
    traceMeta: {
      ...(decision.traceMeta || {}),
      reasons: nextReasons,
      scoreStages: [
        ...existingStages.slice(0, 11),
        stage
      ]
    }
  };
};

const applyTeamBrainScoringV63 = (
  decision: ScoredTeamAiDecision,
  context: TeamBrainContextV63,
  settings: GameSettingsState
): ScoredTeamAiDecision => {
  if (!settings.teamBrainV63Enabled || settings.teamBrainModeV63 === 'classic') return decision;

  let delta = 0;
  const reasons: string[] = [];
  const personality = AI_PERSONALITY_PROFILES_V63[context.actorPersonality] || AI_PERSONALITY_PROFILES_V63.balanced;

  const add = (amount: number, reason: string) => {
    if (!Number.isFinite(amount) || amount === 0) return;
    delta += amount;
    if (Math.abs(amount) >= 10) {
      reasons.push(reason.startsWith('Team Brain:') ? reason : `Team Brain: ${reason}`);
    }
  };

  const lowCash = context.actor.money < 500;
  const veryLowCash = context.actor.money < 300;
  const successChance = getDecisionSuccessChanceV63(decision);
  const actionCost = getDecisionCashCostV63(decision);
  const hasUsefulTeamGoal = Boolean(
    decision.data?.directiveMeta ||
    decision.data?.teamModeMeta?.directiveModeActive ||
    context.teamStrategyMode === 'attack' ||
    context.teamStrategyMode === 'support' ||
    context.teamStrategyMode === 'control' ||
    context.teamStrategyMode === 'resource'
  );
  const protectsCraftSetup = isResourceCloseToHighValueCraftV63(context.actor, decision.data?.resource);

  switch (decision.type) {
    case 'sell':
      add((lowCash ? 90 : 35) * personality.money, 'AI sold resources because team cash was low or cash progress mattered.');
      if (settings.teamBrainRecoveryLogicEnabled && context.teamStrategyMode === 'recovery') {
        add(60, 'Recovery Mode prioritized safe money actions.');
      }
      if (settings.teamBrainResourceLogicEnabled && protectsCraftSetup && !veryLowCash) {
        add(-95, 'AI protected a near-ready high-value craft instead of selling the resource.');
      }
      break;

    case 'challenge':
      add(45 * personality.challenge, 'AI valued challenge progress.');

      if (successChance < 0.45 && !context.teamBehind) {
        add(-80 * settings.teamBrainRiskScaling, 'AI reduced a risky challenge while not behind.');
      }

      if (context.teamBehind && settings.teamBrainComebackLogicEnabled && successChance >= 0.4) {
        add(65 * personality.risk, 'AI took more risk because the team was behind.');
      }

      if (lowCash && successChance < 0.55 && !context.teamBehind) {
        add(-70, 'AI avoided challenge risk because cash was low and the team was not behind.');
      }

      if (veryLowCash && successChance < 0.65) {
        add(-100, 'AI avoided unsafe challenge risk while cash was very low.');
      }
      break;

    case 'travel':
      add(25 * personality.travel, 'AI considered travel for better opportunities.');

      if (settings.teamBrainTravelDisciplineEnabled && lowCash) {
        add(-85 * settings.teamBrainTravelDiscipline, 'AI avoided travel because cash was low.');
      }

      if (settings.teamBrainTravelDisciplineEnabled && !hasUsefulTeamGoal && !context.teamBehind) {
        add(-45 * settings.teamBrainTravelDiscipline, 'AI avoided travel without a clear team goal or better destination.');
      }

      if (context.teamStrategyMode === 'attack') {
        add(25, 'Attack Mode allowed travel toward better opportunities.');
      }

      if (context.teamStrategyMode === 'defense') {
        add(-35, 'Defense Mode avoided unnecessary travel.');
      }

      if (settings.teamBrainRecoveryLogicEnabled && context.teamStrategyMode === 'recovery') {
        add(-70, 'Recovery Mode avoided travel costs.');
      }
      break;

    case 'buy_market':
      if (settings.teamBrainResourceLogicEnabled) {
        add(50 * personality.resource, 'AI valued buying resources for future profit.');
      }

      if (lowCash) {
        add(-65, 'AI reduced buying because cash was low.');
      }
      break;

    case 'craft':
      if (settings.teamBrainResourceLogicEnabled) {
        add(75 * personality.resource, 'AI valued crafting because it can increase resource value.');
      }

      if (settings.teamBrainResourceLogicEnabled && context.teamStrategyMode === 'resource') {
        add(55, 'Resource Mode prioritized crafting and resource conversion.');
      }
      break;

    case 'give_cash':
    case 'give_resource':
      if (settings.teamBrainTeammateSupportEnabled && context.teammateNeedsHelp) {
        add(110 * personality.support * settings.teamBrainTeammateSupportBias, 'AI supported a teammate because recovery help had real value.');
      } else {
        add(-60, 'AI reduced support because teammate help was not urgent.');
      }

      if (lowCash || (actionCost > 0 && context.actor.money - actionCost < 300)) {
        add(-70, 'AI avoided support that could weaken its own cash position too much.');
      }
      break;

    case 'sabotage':
      add(45 * personality.sabotage, 'AI considered sabotage against opponents.');

      if (settings.teamBrainOpponentPressureEnabled && (context.teamBehind || context.opponentIsAhead)) {
        add(85 * settings.teamBrainOpponentPressureBias, 'AI used pressure logic to slow the leading team.');
      }

      if (!settings.teamBrainOpponentPressureEnabled && !context.teamBehind && !context.opponentIsAhead) {
        add(-35, 'AI reduced sabotage because pressure logic did not identify a meaningful target advantage.');
      }

      if (context.teamAhead) {
        add(-70, 'AI reduced sabotage because the team was already ahead.');
      }

      if (lowCash) {
        add(-85, 'AI reduced sabotage because cash was low.');
      }
      break;

    case 'invest':
      add(55 * personality.invest, 'AI valued long-term investment.');

      if (context.teamStrategyMode === 'defense') {
        add(35, 'Defense Mode favored durable value.');
      }

      if (lowCash || (settings.teamBrainRecoveryLogicEnabled && context.teamStrategyMode === 'recovery')) {
        add(-90, 'AI reduced investment because recovery cash was needed.');
      }
      break;

    case 'region_deposit':
      add(60 * personality.control, 'AI valued region control.');

      if (context.teamStrategyMode === 'control') {
        add(70, 'Control Mode prioritized region pressure.');
      }

      if (settings.teamBrainRecoveryLogicEnabled && context.teamStrategyMode === 'recovery' && settings.winCondition !== 'regions') {
        add(-80, 'Recovery Mode avoided non-essential region spending.');
      }
      break;

    case 'cashout_region':
      if (lowCash || (settings.teamBrainRecoveryLogicEnabled && context.teamStrategyMode === 'recovery')) {
        add(95, 'AI cashed out to recover team cash.');
      }

      if (settings.winCondition === 'regions' && !lowCash) {
        add(-85, 'AI avoided weakening region control.');
      }
      break;
  }

  const nextScore = decision.score + delta;
  return appendDecisionScoreStageV63({
    ...decision,
    score: nextScore
  }, {
    id: 'team_brain_v63',
    label: 'Team Brain V6.3',
    score: nextScore,
    delta,
    reason: reasons[0] || 'Team Brain made no major adjustment.'
  }, reasons, settings.teamBrainExplanationEnabled);
};

const applyAiStrategyLabOverlayV63 = <T extends AIAction & { score: number }>(
  decision: T,
  context: {
    modeKind: AiStrategyLabModeKind;
    actor: ActorState;
    settings: GameSettingsState;
    relationshipLabel: ActorRelationshipLabel;
    teamContext?: AiStrategyLabTeamOverlayContext | null;
    opponentContext?: AiStrategyLabOpponentOverlayContext | null;
  }
): T => {
  let scoreDelta = 0;
  const reasons: string[] = [];

  const actorPreset = getAiStrategyPresetForActorV63(
    context.relationshipLabel,
    context.settings
  );

  const activeFactors = context.settings.aiStrategyLabSeparateProfilesEnabled
    ? applyAiStrategyLabPresetV63(
        context.settings.aiEvaluationFactors,
        actorPreset,
        context.settings
      )
    : cloneAiEvaluationFactorsV63(context.settings.aiEvaluationFactors);

  const getFactor = (id: AiEvaluationFactorId) =>
    activeFactors.find(factor =>
      factor.id === id &&
      factor.enabled &&
      factor.appliesTo.includes(context.modeKind)
    );

  const addFactor = (
    id: AiEvaluationFactorId,
    baseDelta: number,
    reason: string
  ) => {
    const factor = getFactor(id);
    if (!factor) return;

    const delta = baseDelta * factor.weight;
    scoreDelta += delta;

    if (Math.abs(delta) >= 10) {
      reasons.push(`${factor.label}: ${reason}`);
    }
  };

  const lowCash = context.actor.money < 500;
  const veryLowCash = context.actor.money < 300;
  const successChance = getDecisionSuccessChanceV63(decision);
  const actionCost = getDecisionCashCostV63(decision);
  const protectsCraftSetup = isResourceCloseToHighValueCraftV63(context.actor, decision.data?.resource);

  const teamBehind = Boolean(
    context.teamContext?.teamBehind ||
    context.teamContext?.opponentLead > 0
  );

  const teamAhead = Boolean(context.teamContext?.teamAhead);

  const teammateWeakness = Boolean(
    context.teamContext?.teammateWeakness ||
    context.teamContext?.teammateNeedsHelp
  );
  const hasUsefulTravelGoal = Boolean(
    decision.data?.directiveMeta ||
    decision.data?.teamModeMeta?.directiveModeActive ||
    context.teamContext?.craftingOpportunity ||
    context.teamContext?.activeDirectives?.length ||
    teamBehind
  );

  switch (decision.type) {
    case 'sell':
      addFactor('profit', lowCash ? 80 : 35, 'selling improves cash.');
      addFactor('resource', 20, 'resource trading is valued.');
      if (protectsCraftSetup && !veryLowCash) {
        addFactor('resource', -80, 'selling would break a near-ready high-value craft.');
      }
      break;

    case 'challenge':
      addFactor('challenge', 55, 'challenge reward is valuable.');
      addFactor('profit', 35, 'challenge can earn money.');
      addFactor('risk', veryLowCash ? -80 : -25, 'challenge has failure risk.');

      if (lowCash && successChance < 0.55 && !teamBehind) {
        addFactor('cash_safety', -65, 'cash is low and the challenge is not reliable enough.');
      }

      if (successChance < 0.4 && !teamBehind) {
        addFactor('risk', -65, 'success chance is too low without comeback pressure.');
      }

      if (teamBehind) {
        addFactor('comeback', 45, 'AI is behind and needs higher-upside plays.');
        if (successChance >= 0.4) {
          addFactor('risk', 20, 'comeback pressure allows a measured risk.');
        }
      }
      break;

    case 'travel':
      addFactor('travel', 45, 'travel may unlock better regions.');
      addFactor('cash_safety', lowCash ? -75 : -20, 'travel costs money.');
      if (lowCash && !hasUsefulTravelGoal) {
        addFactor('travel', -55, 'destination did not clearly support a challenge, resource, or team goal.');
      }
      break;

    case 'buy_market':
      addFactor('resource', 60, 'buying resources can unlock future profit.');
      addFactor('cash_safety', lowCash ? -70 : -20, 'buying reduces cash.');
      break;

    case 'craft':
      addFactor('resource', 70, 'crafting can turn resources into higher value.');
      addFactor('profit', 45, 'crafted items can produce stronger profit.');
      break;

    case 'give_cash':
    case 'give_resource':
      addFactor('support', teammateWeakness ? 95 : -45, teammateWeakness ? 'support helps a teammate who needs help.' : 'support was not needed right now.');
      addFactor('coordination', teammateWeakness ? 55 : -20, teammateWeakness ? 'team coordination values shared progress.' : 'coordination avoided wasteful support.');
      addFactor('shared_cash', lowCash ? -60 : -15, 'support should not bankrupt the actor.');
      if (actionCost > 0 && context.actor.money - actionCost < 300) {
        addFactor('shared_cash', -80, 'support would leave the actor nearly broke.');
      }
      break;

    case 'sabotage':
      addFactor('sabotage', 65, 'sabotage slows opponents.');
      addFactor('cash_safety', lowCash ? -85 : -30, 'sabotage is expensive.');

      if (teamBehind) {
        addFactor('comeback', 70, 'sabotage can help a losing team catch up.');
      }
      if (teamAhead) {
        addFactor('sabotage', -70, 'AI is already ahead and should avoid low-value sabotage.');
      }
      break;

    case 'invest':
      addFactor('long_term', 80, 'investment improves future income.');
      addFactor('cash_safety', lowCash ? -90 : -35, 'investment uses cash now.');
      break;

    case 'region_deposit':
      addFactor('region_control', 80, 'region control helps territory wins.');
      addFactor('cash_safety', lowCash ? -70 : -25, 'region deposits reduce cash.');
      break;
  }

  const nextScore = decision.score + scoreDelta;
  return appendDecisionScoreStageV63({
    ...decision,
    score: nextScore
  }, {
    id: 'ai_strategy_lab_v63',
    label: 'AI Strategy Lab',
    score: nextScore,
    delta: scoreDelta,
    reason: reasons[0] || 'AI Strategy Lab made no major adjustment.'
  }, reasons, true);
};

// V6.7 Phase 2a: transparency-only overlay stage for Competitive AI Action Overrides.
// Deliberately zero score delta — this stage exists to surface override eligibility in
// Decision Transparency, not to change ranking (that would be a much larger behavior
// change than the spec asks for). Uses its own distinct stage id, never reused elsewhere.
const applyCompetitiveAiOverrideOverlayV67 = <T extends AIAction & { score: number }>(
  decision: T,
  settings: GameSettingsState,
  overrideOverlayContext: V63AiOverlayContext['overrideOverlayContext']
): T => {
  const info = overrideOverlayContext?.byDecisionType?.[decision.type];
  if (!info) return decision;
  return appendDecisionScoreStageV63(decision, {
    id: 'competitive_ai_override_v67',
    label: 'Competitive AI: Action Override',
    score: decision.score,
    delta: 0,
    reason: info.eligible
      ? `Override eligible (${info.reasonLabel}, cost $${info.cost}).`
      : `Override not eligible (${info.reasonLabel}).`
  }, [], settings.teamAiOverrideTransparencyEnabled);
};

// V6.7 Phase 3d: transparency-only overlay stage for the Shared Action Bank, mirroring
// applyCompetitiveAiOverrideOverlayV67 exactly (zero score delta).
const applyTeamActionBankOverlayV67 = <T extends AIAction & { score: number }>(
  decision: T,
  settings: GameSettingsState,
  bankDrawOverlayContext: V63AiOverlayContext['bankDrawOverlayContext']
): T => {
  const info = bankDrawOverlayContext?.byDecisionType?.[decision.type];
  if (!info) return decision;
  return appendDecisionScoreStageV63(decision, {
    id: 'team_action_bank_v67',
    label: 'Shared Action Bank',
    score: decision.score,
    delta: 0,
    reason: info.eligible
      ? `Could draw a free action from the Shared Team Bank (${info.reasonLabel}).`
      : `Shared Team Bank draw not available (${info.reasonLabel}).`
  }, [], settings.teamActionBankTransparencyEnabled);
};

// V6.7 Phase 3d: transparency-only overlay stage for Emergency Actions, mirroring
// applyCompetitiveAiOverrideOverlayV67 exactly (zero score delta).
const applyTeamEmergencyActionOverlayV67 = <T extends AIAction & { score: number }>(
  decision: T,
  settings: GameSettingsState,
  emergencyOverlayContext: V63AiOverlayContext['emergencyOverlayContext']
): T => {
  const info = emergencyOverlayContext?.byDecisionType?.[decision.type];
  if (!info) return decision;
  return appendDecisionScoreStageV63(decision, {
    id: 'team_emergency_action_v67',
    label: 'Emergency Actions',
    score: decision.score,
    delta: 0,
    reason: info.eligible
      ? `An Emergency Action is available this turn (${info.reasonLabel}).`
      : `No Emergency Action available (${info.reasonLabel}).`
  }, [], settings.teamAiEmergencyActionsTransparencyEnabled);
};

const applyV63AiOverlays = <T extends AIAction & { score: number }>(
  originalDecisions: T[],
  context: V63AiOverlayContext
): T[] => {
  let decisions = originalDecisions;
  const modeKind = getAiStrategyLabModeKind(context.selectedMode);

  if (
    modeKind &&
    shouldUseAiStrategyLabForMode(context.selectedMode, context.settings)
  ) {
    decisions = decisions.map(decision =>
      applyAiStrategyLabOverlayV63(decision, {
        modeKind,
        actor: context.actor,
        settings: context.settings,
        relationshipLabel: context.relationshipLabel,
        teamContext: context.strategyLabTeamContext,
        opponentContext: context.opponentContext
      })
    );
  }

  if (
    isTeamModeSelection(context.selectedMode) &&
    context.settings.teamBrainV63Enabled &&
    context.settings.teamBrainModeV63 !== 'classic' &&
    context.teamBrainContext
  ) {
    decisions = decisions.map(decision =>
      applyTeamBrainScoringV63(
        decision as ScoredTeamAiDecision,
        context.teamBrainContext as TeamBrainContextV63,
        context.settings
      ) as unknown as T
    );
  }

  if (
    context.settings.teamCompetitiveAiEnabled &&
    context.settings.teamAiActionOverridesEnabled &&
    context.overrideOverlayContext
  ) {
    decisions = decisions.map(decision =>
      applyCompetitiveAiOverrideOverlayV67(decision, context.settings, context.overrideOverlayContext)
    );
  }

  if (
    context.settings.teamCompetitiveAiEnabled &&
    context.settings.teamActionBankEnabled &&
    context.bankDrawOverlayContext
  ) {
    decisions = decisions.map(decision =>
      applyTeamActionBankOverlayV67(decision, context.settings, context.bankDrawOverlayContext)
    );
  }

  if (
    context.settings.teamCompetitiveAiEnabled &&
    context.settings.teamAiEmergencyActionsEnabled &&
    context.emergencyOverlayContext
  ) {
    decisions = decisions.map(decision =>
      applyTeamEmergencyActionOverlayV67(decision, context.settings, context.emergencyOverlayContext)
    );
  }

  return decisions;
};

const normalizeAdvancedLoansAccessMode = (value: unknown): AdvancedLoansAccessMode => {
  if (value === 'ai_only' || value === 'both') return value;
  return 'player_only';
};

const sanitizeAdaptiveAiAffectedModes = (value: unknown): AdaptiveAiAffectedMode[] => {
  const defaults = [...DEFAULT_GAME_SETTINGS.adaptiveAiAffectedModes];
  if (!Array.isArray(value)) return defaults;
  const allowed: AdaptiveAiAffectedMode[] = ['ai', 'grand_tour', 'team_human_ai_vs_ai_ai', 'team_ai_vs_ai'];
  const nextModes = value.filter((entry): entry is AdaptiveAiAffectedMode => allowed.includes(entry as AdaptiveAiAffectedMode));
  return nextModes.length > 0 ? Array.from(new Set(nextModes)) : defaults;
};

const sanitizeSupportRequest = (value: unknown): SupportRequest | null => {
  if (!value || typeof value !== 'object') return null;
  const source = value as Partial<SupportRequest>;
  if (typeof source.id !== 'string' || (source.type !== 'cash' && source.type !== 'resource' && source.type !== 'cover' && source.type !== 'help')) {
    return null;
  }
  const normalizedStatus = source.status === 'resolved' || source.status === 'ignored' || source.status === 'expired'
    ? source.status
    : 'open';
  return {
    id: source.id,
    type: source.type,
    reason: typeof source.reason === 'string' ? source.reason : '',
    priority: Math.max(1, Math.min(5, Math.floor(Number(source.priority) || 1))),
    status: normalizedStatus,
    createdTurn: Math.max(0, Math.floor(Number(source.createdTurn) || 0)),
    expiresTurn: Math.max(
      0,
      Math.floor(
        Number(source.expiresTurn)
        || Number(source.createdTurn)
        || 0
      )
    ),
    requestMode: source.requestMode === 'remote' ? 'remote' : 'local',
    targetActorId: typeof source.targetActorId === 'string' ? source.targetActorId : undefined,
    region: typeof source.region === 'string' ? source.region : undefined,
    resource: typeof source.resource === 'string' ? source.resource : undefined,
    amount: Number.isFinite(source.amount as number) ? Math.max(0, Math.floor(Number(source.amount) || 0)) : undefined,
    fulfilledByActorId: typeof source.fulfilledByActorId === 'string' ? source.fulfilledByActorId : undefined
  };
};

const sanitizeSupportRequests = (value: unknown): SupportRequest[] => {
  if (!Array.isArray(value)) return [];
  return value
    .map(entry => sanitizeSupportRequest(entry))
    .filter((entry): entry is SupportRequest => Boolean(entry))
    .slice(-12);
};

const sanitizeTeamSupportLedger = (value: unknown): TeamSupportLedger => {
  const defaults = createDefaultTeamSupportLedger();
  if (!value || typeof value !== 'object') return defaults;
  const source = value as Partial<TeamSupportLedger>;
  const sanitizeNumericRecord = (record: unknown) => {
    if (!record || typeof record !== 'object') return {} as Record<string, number>;
    return Object.entries(record as Record<string, unknown>).reduce<Record<string, number>>((acc, [key, amount]) => {
      if (typeof amount === 'number' && isFinite(amount)) {
        acc[key] = Math.max(0, Math.floor(amount));
      }
      return acc;
    }, {});
  };
  const sanitizeStringRecord = (record: unknown) => {
    if (!record || typeof record !== 'object') return {} as Record<string, string>;
    return Object.entries(record as Record<string, unknown>).reduce<Record<string, string>>((acc, [key, entry]) => {
      if (typeof entry === 'string' && entry.trim()) {
        acc[key] = entry;
      }
      return acc;
    }, {});
  };
  return {
    cashByActor: sanitizeNumericRecord(source.cashByActor),
    resourcesByActor: sanitizeNumericRecord(source.resourcesByActor),
    lowCashTurnsByActor: sanitizeNumericRecord(source.lowCashTurnsByActor),
    underfundedTurnsByActor: sanitizeNumericRecord(source.underfundedTurnsByActor),
    carryingTurnsByActor: sanitizeNumericRecord(source.carryingTurnsByActor),
    lastCashTransferTurnByPair: sanitizeNumericRecord(source.lastCashTransferTurnByPair),
    lastResourceTransferTurnByPair: sanitizeNumericRecord(source.lastResourceTransferTurnByPair),
    lastRemoteAidTurnByPair: sanitizeNumericRecord(source.lastRemoteAidTurnByPair),
    lastSupportReasonByActor: sanitizeStringRecord(source.lastSupportReasonByActor),
    lastActionLendTurnByPair: sanitizeNumericRecord(source.lastActionLendTurnByPair)
  };
};

// V6.7 Phase 2b: Shared Team Action Bank sanitizer, mirroring sanitizeTeamSupportLedger's shape
const sanitizeTeamActionBank = (value: unknown): TeamActionBankState => {
  const defaults = createDefaultTeamActionBankState();
  if (!value || typeof value !== 'object') return defaults;
  const source = value as Partial<TeamActionBankState>;
  const balance = typeof source.balance === 'number' && isFinite(source.balance)
    ? Math.max(0, Math.floor(source.balance))
    : defaults.balance;
  const drawsUsedTodayByActor = (source.drawsUsedTodayByActor && typeof source.drawsUsedTodayByActor === 'object')
    ? Object.entries(source.drawsUsedTodayByActor).reduce<Record<string, number>>((acc, [actorId, count]) => {
        if (typeof count === 'number' && isFinite(count)) acc[actorId] = Math.max(0, Math.floor(count));
        return acc;
      }, {})
    : defaults.drawsUsedTodayByActor;
  const lastDrawDay = typeof source.lastDrawDay === 'number' && isFinite(source.lastDrawDay)
    ? Math.max(0, Math.floor(source.lastDrawDay))
    : defaults.lastDrawDay;
  return { balance, drawsUsedTodayByActor, lastDrawDay };
};

const TREASURY_TRANSACTION_TYPES: TreasuryTransactionType[] = [
  'manual_contribution', 'automatic_contribution', 'excess_cash_contribution',
  'manual_withdrawal', 'approved_funding_request', 'partial_funding_approval',
  'emergency_zero_cash_support', 'refund', 'unused_funds_return'
];

// Team Treasury Phase T1: default reserve/balance are read from settings by the caller where
// needed; the state factory itself just needs a structurally valid, all-zero starting point.
const createDefaultTeamTreasuryState = (teamId: string): TeamTreasuryState => ({
  teamId,
  balance: 0,
  totalContributed: 0,
  totalWithdrawn: 0,
  reserve: 0,
  transactions: [],
  pendingFundingRequestIds: [],
  fundingRequests: [],
  contributionTotalsByActor: {},
  withdrawalTotalsByActor: {},
  lastContributionDay: {},
  lastWithdrawalDay: {}
});

// Team Treasury Phase T1: a malformed transaction is dropped entirely rather than coerced,
// matching the ActionToken/messageLog sanitization convention above.
const sanitizeTreasuryTransaction = (value: unknown): TreasuryTransaction | null => {
  if (!value || typeof value !== 'object') return null;
  const source = value as Partial<TreasuryTransaction>;
  if (typeof source.id !== 'string' || typeof source.teamId !== 'string') return null;
  if (!TREASURY_TRANSACTION_TYPES.includes(source.type as TreasuryTransactionType)) return null;
  if (typeof source.amount !== 'number' || !isFinite(source.amount)) return null;
  return {
    id: source.id,
    day: typeof source.day === 'number' && isFinite(source.day) ? Math.max(0, Math.floor(source.day)) : 0,
    turn: typeof source.turn === 'number' && isFinite(source.turn) ? Math.max(0, Math.floor(source.turn)) : 0,
    teamId: source.teamId,
    actorId: typeof source.actorId === 'string' ? source.actorId : null,
    type: source.type as TreasuryTransactionType,
    amount: Math.max(0, source.amount),
    balanceBefore: typeof source.balanceBefore === 'number' && isFinite(source.balanceBefore) ? Math.max(0, source.balanceBefore) : 0,
    balanceAfter: typeof source.balanceAfter === 'number' && isFinite(source.balanceAfter) ? Math.max(0, source.balanceAfter) : 0,
    reason: typeof source.reason === 'string' ? source.reason : '',
    relatedActionType: typeof source.relatedActionType === 'string' ? source.relatedActionType as AIAction['type'] : undefined,
    fundingRequestId: typeof source.fundingRequestId === 'string' ? source.fundingRequestId : undefined,
    automatic: Boolean(source.automatic)
  };
};

const TREASURY_FUNDING_REQUEST_TYPES: TreasuryFundingRequestType[] = ['emergency_cash', 'fund_specific_action', 'custom'];
const TREASURY_FUNDING_REQUEST_STATUSES: TreasuryFundingRequestStatus[] = [
  'pending', 'approved', 'partially_approved', 'rejected', 'cancelled', 'expired', 'fulfilled'
];

// Team Treasury Phase T2: a malformed funding request is dropped entirely, matching
// sanitizeTreasuryTransaction's convention above.
const sanitizeTreasuryFundingRequest = (value: unknown): TreasuryFundingRequest | null => {
  if (!value || typeof value !== 'object') return null;
  const source = value as Partial<TreasuryFundingRequest>;
  if (typeof source.id !== 'string' || typeof source.requestingActorId !== 'string' || typeof source.requestingTeamId !== 'string') return null;
  if (!TREASURY_FUNDING_REQUEST_TYPES.includes(source.requestType as TreasuryFundingRequestType)) return null;
  if (!TREASURY_FUNDING_REQUEST_STATUSES.includes(source.status as TreasuryFundingRequestStatus)) return null;
  if (typeof source.requestedAmount !== 'number' || !isFinite(source.requestedAmount)) return null;
  return {
    id: source.id,
    requestingActorId: source.requestingActorId,
    requestingTeamId: source.requestingTeamId,
    requestType: source.requestType as TreasuryFundingRequestType,
    requestedAmount: Math.max(0, source.requestedAmount),
    approvedAmount: typeof source.approvedAmount === 'number' && isFinite(source.approvedAmount) ? Math.max(0, source.approvedAmount) : null,
    intendedActionType: typeof source.intendedActionType === 'string' ? source.intendedActionType as AIAction['type'] : undefined,
    intendedActionCost: typeof source.intendedActionCost === 'number' && isFinite(source.intendedActionCost) ? Math.max(0, source.intendedActionCost) : undefined,
    expectedBenefit: typeof source.expectedBenefit === 'number' && isFinite(source.expectedBenefit) ? source.expectedBenefit : undefined,
    reason: typeof source.reason === 'string' ? source.reason : '',
    status: source.status as TreasuryFundingRequestStatus,
    createdDay: typeof source.createdDay === 'number' && isFinite(source.createdDay) ? Math.max(0, Math.floor(source.createdDay)) : 0,
    createdTurn: typeof source.createdTurn === 'number' && isFinite(source.createdTurn) ? Math.max(0, Math.floor(source.createdTurn)) : 0,
    resolvedDay: typeof source.resolvedDay === 'number' && isFinite(source.resolvedDay) ? Math.max(0, Math.floor(source.resolvedDay)) : undefined,
    fulfilledAmountSpent: typeof source.fulfilledAmountSpent === 'number' && isFinite(source.fulfilledAmountSpent) ? Math.max(0, source.fulfilledAmountSpent) : undefined,
    unusedAmountReturned: typeof source.unusedAmountReturned === 'number' && isFinite(source.unusedAmountReturned) ? Math.max(0, source.unusedAmountReturned) : undefined
  };
};

const GOVERNOR_EXCEPTION_SCOPES: GovernorExceptionScope[] = ['single_action', 'current_turn', 'until_recovery_target', 'temporary_reserve_reduction'];
const GOVERNOR_EXCEPTION_STATUSES: GovernorExceptionStatus[] = ['pending', 'approved', 'rejected', 'expired', 'consumed'];
const ECONOMY_SPEND_CATEGORIES: EconomySpendCategory[] = ['equipment', 'investment', 'sabotage', 'region_deposit', 'travel', 'override', 'support'];

// Team Treasury Phase T4: a malformed Governor exception is dropped entirely, matching
// sanitizeTreasuryFundingRequest's convention above.
const sanitizeTeamGovernorException = (value: unknown): TeamGovernorException | null => {
  if (!value || typeof value !== 'object') return null;
  const source = value as Partial<TeamGovernorException>;
  if (typeof source.id !== 'string' || typeof source.actorId !== 'string' || typeof source.teamId !== 'string') return null;
  if (!GOVERNOR_EXCEPTION_SCOPES.includes(source.scope as GovernorExceptionScope)) return null;
  if (!GOVERNOR_EXCEPTION_STATUSES.includes(source.status as GovernorExceptionStatus)) return null;
  const allowedCategories = Array.isArray(source.allowedCategories)
    ? source.allowedCategories.filter((c): c is EconomySpendCategory => ECONOMY_SPEND_CATEGORIES.includes(c as EconomySpendCategory))
    : [];
  return {
    id: source.id,
    actorId: source.actorId,
    teamId: source.teamId,
    scope: source.scope as GovernorExceptionScope,
    allowedCategories,
    maxReserveBreach: typeof source.maxReserveBreach === 'number' && isFinite(source.maxReserveBreach) ? Math.max(0, source.maxReserveBreach) : 0,
    reserveReductionAmount: typeof source.reserveReductionAmount === 'number' && isFinite(source.reserveReductionAmount) ? Math.max(0, source.reserveReductionAmount) : undefined,
    expiresDay: typeof source.expiresDay === 'number' && isFinite(source.expiresDay) ? Math.max(0, Math.floor(source.expiresDay)) : undefined,
    status: source.status as GovernorExceptionStatus,
    reason: typeof source.reason === 'string' ? source.reason : '',
    createdDay: typeof source.createdDay === 'number' && isFinite(source.createdDay) ? Math.max(0, Math.floor(source.createdDay)) : 0,
    resolvedDay: typeof source.resolvedDay === 'number' && isFinite(source.resolvedDay) ? Math.max(0, Math.floor(source.resolvedDay)) : undefined
  };
};

const sanitizeTeamGovernorExceptions = (value: unknown): TeamGovernorException[] =>
  Array.isArray(value)
    ? value.map(sanitizeTeamGovernorException).filter((e): e is TeamGovernorException => e !== null).slice(-30)
    : [];

// Team Treasury Phase T1: mirrors sanitizeTeamActionBank's always-valid-object style (never
// null — a team always has a treasury record once the field exists) — capped to the last 60
// transactions, same cap precedent as actionTokens/messageLog.
const sanitizeTeamTreasuryState = (value: unknown, teamId: string): TeamTreasuryState => {
  const defaults = createDefaultTeamTreasuryState(teamId);
  if (!value || typeof value !== 'object') return defaults;
  const source = value as Partial<TeamTreasuryState>;
  const numberField = (field: number | undefined, fallback: number) =>
    typeof field === 'number' && isFinite(field) ? Math.max(0, field) : fallback;
  const recordField = (field: unknown, fallback: Record<string, number>) =>
    (field && typeof field === 'object')
      ? Object.entries(field as Record<string, unknown>).reduce<Record<string, number>>((acc, [key, val]) => {
          if (typeof val === 'number' && isFinite(val)) acc[key] = Math.max(0, val);
          return acc;
        }, {})
      : fallback;
  return {
    teamId,
    balance: numberField(source.balance, defaults.balance),
    totalContributed: numberField(source.totalContributed, defaults.totalContributed),
    totalWithdrawn: numberField(source.totalWithdrawn, defaults.totalWithdrawn),
    reserve: numberField(source.reserve, defaults.reserve),
    transactions: Array.isArray(source.transactions)
      ? source.transactions.map(sanitizeTreasuryTransaction).filter((t): t is TreasuryTransaction => t !== null).slice(-60)
      : defaults.transactions,
    pendingFundingRequestIds: Array.isArray(source.pendingFundingRequestIds)
      ? source.pendingFundingRequestIds.filter((id): id is string => typeof id === 'string')
      : defaults.pendingFundingRequestIds,
    fundingRequests: Array.isArray(source.fundingRequests)
      ? source.fundingRequests.map(sanitizeTreasuryFundingRequest).filter((r): r is TreasuryFundingRequest => r !== null).slice(-60)
      : defaults.fundingRequests,
    contributionTotalsByActor: recordField(source.contributionTotalsByActor, defaults.contributionTotalsByActor),
    withdrawalTotalsByActor: recordField(source.withdrawalTotalsByActor, defaults.withdrawalTotalsByActor),
    lastContributionDay: recordField(source.lastContributionDay, defaults.lastContributionDay),
    lastWithdrawalDay: recordField(source.lastWithdrawalDay, defaults.lastWithdrawalDay)
  };
};

const ACTION_TOKEN_SOURCES: ActionTokenSource[] = ['normal', 'shared_bank', 'lent', 'override', 'initiative', 'emergency', 'sequence', 'treasury'];
const ACTION_TOKEN_STATUSES: ActionTokenStatus[] = ['granted', 'consumed', 'invalidated'];

// V6.7 Phase 3a: never trust a persisted enum blindly (same convention as activeReservations/
// messageLog sanitization) — a malformed token is dropped entirely rather than coerced.
const sanitizeActionToken = (value: unknown): ActionToken | null => {
  if (!value || typeof value !== 'object') return null;
  const source = value as Partial<ActionToken>;
  if (typeof source.id !== 'string' || typeof source.teamId !== 'string' || typeof source.actorId !== 'string') return null;
  if (!ACTION_TOKEN_SOURCES.includes(source.source as ActionTokenSource)) return null;
  if (!ACTION_TOKEN_STATUSES.includes(source.status as ActionTokenStatus)) return null;
  if (typeof source.grantedTurn !== 'number' || !isFinite(source.grantedTurn)) return null;
  return {
    id: source.id,
    teamId: source.teamId,
    actorId: source.actorId,
    source: source.source as ActionTokenSource,
    grantedTurn: Math.max(0, Math.floor(source.grantedTurn)),
    status: source.status as ActionTokenStatus,
    consumedTurn: typeof source.consumedTurn === 'number' && isFinite(source.consumedTurn) ? Math.max(0, Math.floor(source.consumedTurn)) : undefined,
    consumedActionType: typeof source.consumedActionType === 'string' ? source.consumedActionType as AIAction['type'] : undefined,
    planId: typeof source.planId === 'string' ? source.planId : undefined,
    invalidatedReason: typeof source.invalidatedReason === 'string' ? source.invalidatedReason : undefined,
    overridesUsedTodayAtMint: typeof source.overridesUsedTodayAtMint === 'number' && isFinite(source.overridesUsedTodayAtMint)
      ? Math.max(0, Math.floor(source.overridesUsedTodayAtMint))
      : undefined
  };
};

const sanitizeActionTokens = (value: unknown): ActionToken[] => {
  if (!Array.isArray(value)) return [];
  return value
    .map(entry => sanitizeActionToken(entry))
    .filter((token): token is ActionToken => Boolean(token))
    .slice(-60);
};

const TEAM_PLAN_TYPES: TeamPlanType[] = [
  'resource_chain', 'crafting_chain', 'region_control_push', 'challenge_push',
  'economic_recovery', 'teammate_support', 'sabotage_followup', 'investment_setup',
  'endgame_conversion', 'block_opponent_win'
];
const TEAM_PLAN_STATUSES: TeamPlanStatus[] = ['proposed', 'active', 'blocked', 'completed', 'abandoned'];
const TEAM_PLAN_INTERRUPTION_REASONS: TeamPlanInterruptionReason[] = [
  'action_illegal', 'resource_unavailable', 'opponent_immediate_win_threat',
  'actor_financial_danger', 'expected_value_collapsed', 'completion_impossible', 'stronger_opportunity'
];
const TEAM_PLAN_STEP_STATUSES: TeamPlanStep['status'][] = ['pending', 'in_progress', 'done', 'skipped', 'failed'];
const TEAM_RESERVATION_TARGET_KINDS: TeamReservationTargetKind[] = ['region', 'resource', 'recipe', 'challenge'];

const sanitizeTeamPlanStep = (value: unknown): TeamPlanStep | null => {
  if (!value || typeof value !== 'object') return null;
  const source = value as Partial<TeamPlanStep>;
  if (typeof source.id !== 'string' || typeof source.assignedActorId !== 'string' || typeof source.actionType !== 'string') return null;
  if (!TEAM_PLAN_STEP_STATUSES.includes(source.status as TeamPlanStep['status'])) return null;
  const requiredResources = (source.requiredResources && typeof source.requiredResources === 'object')
    ? Object.entries(source.requiredResources).reduce<Record<string, number>>((acc, [resource, qty]) => {
        if (typeof qty === 'number' && isFinite(qty)) acc[resource] = Math.max(0, Math.floor(qty));
        return acc;
      }, {})
    : {};
  return {
    id: source.id,
    order: typeof source.order === 'number' && isFinite(source.order) ? source.order : 0,
    assignedActorId: source.assignedActorId,
    actionType: source.actionType as AIAction['type'],
    dependsOnStepIds: Array.isArray(source.dependsOnStepIds) ? source.dependsOnStepIds.filter(id => typeof id === 'string') : [],
    requiredCash: typeof source.requiredCash === 'number' && isFinite(source.requiredCash) ? Math.max(0, Math.floor(source.requiredCash)) : 0,
    requiredResources,
    targetKind: TEAM_RESERVATION_TARGET_KINDS.includes(source.targetKind as TeamReservationTargetKind) ? source.targetKind as TeamReservationTargetKind : undefined,
    targetId: typeof source.targetId === 'string' ? source.targetId : undefined,
    status: source.status as TeamPlanStep['status'],
    fallbackActionType: typeof source.fallbackActionType === 'string' ? source.fallbackActionType as AIAction['type'] : undefined,
    overridePermitted: Boolean(source.overridePermitted),
    actionTokenSource: ACTION_TOKEN_SOURCES.includes(source.actionTokenSource as ActionTokenSource) ? source.actionTokenSource as ActionTokenSource : 'normal'
  };
};

// V6.7 Phase 3a: returns null on any malformed shape rather than resuming a plan in an unknown
// state — matching the file's general "never trust persisted enums blindly" convention.
const sanitizeTeamPlan = (value: unknown): TeamPlan | null => {
  if (!value || typeof value !== 'object') return null;
  const source = value as Partial<TeamPlan>;
  if (typeof source.id !== 'string' || typeof source.teamId !== 'string') return null;
  if (!TEAM_PLAN_TYPES.includes(source.type as TeamPlanType)) return null;
  if (!TEAM_PLAN_STATUSES.includes(source.status as TeamPlanStatus)) return null;
  const steps = Array.isArray(source.steps)
    ? source.steps.map(step => sanitizeTeamPlanStep(step)).filter((step): step is TeamPlanStep => Boolean(step))
    : [];
  const reservedResources = (source.reservedResources && typeof source.reservedResources === 'object')
    ? Object.entries(source.reservedResources).reduce<Record<string, number>>((acc, [resource, qty]) => {
        if (typeof qty === 'number' && isFinite(qty)) acc[resource] = Math.max(0, Math.floor(qty));
        return acc;
      }, {})
    : {};
  return {
    id: source.id,
    type: source.type as TeamPlanType,
    teamId: source.teamId,
    objective: typeof source.objective === 'string' ? source.objective : '',
    priority: typeof source.priority === 'number' && isFinite(source.priority) ? source.priority : 1,
    status: source.status as TeamPlanStatus,
    createdDay: typeof source.createdDay === 'number' && isFinite(source.createdDay) ? Math.max(0, Math.floor(source.createdDay)) : 0,
    expiresDay: typeof source.expiresDay === 'number' && isFinite(source.expiresDay) ? Math.max(0, Math.floor(source.expiresDay)) : 0,
    assignedActorIds: Array.isArray(source.assignedActorIds) ? source.assignedActorIds.filter(id => typeof id === 'string') : [],
    steps,
    reservedCash: typeof source.reservedCash === 'number' && isFinite(source.reservedCash) ? Math.max(0, Math.floor(source.reservedCash)) : 0,
    reservedResources,
    expectedValue: typeof source.expectedValue === 'number' && isFinite(source.expectedValue) ? source.expectedValue : 0,
    interruptionThreshold: typeof source.interruptionThreshold === 'number' && isFinite(source.interruptionThreshold) ? source.interruptionThreshold : 0,
    failureReason: TEAM_PLAN_INTERRUPTION_REASONS.includes(source.failureReason as TeamPlanInterruptionReason) ? source.failureReason as TeamPlanInterruptionReason : undefined
  };
};

const sanitizeTeamPlanHistory = (value: unknown): TeamPlan[] => {
  if (!Array.isArray(value)) return [];
  return value
    .map(entry => sanitizeTeamPlan(entry))
    .filter((plan): plan is TeamPlan => Boolean(plan))
    .slice(-10);
};

// V6.7 Phase 3b: mirrors sanitizeTeamPlan's null-on-malformed-shape convention.
const sanitizeTeamThreatTarget = (value: unknown): TeamThreatTargetState | null => {
  if (!value || typeof value !== 'object') return null;
  const source = value as Partial<TeamThreatTargetState>;
  if (typeof source.targetActorId !== 'string') return null;
  return {
    targetActorId: source.targetActorId,
    selectedTurn: typeof source.selectedTurn === 'number' && isFinite(source.selectedTurn) ? Math.max(0, Math.floor(source.selectedTurn)) : 0,
    score: typeof source.score === 'number' && isFinite(source.score) ? source.score : 0,
    reasonSummary: typeof source.reasonSummary === 'string' ? source.reasonSummary : ''
  };
};

const EMERGENCY_REASON_TAGS: EmergencyReasonTag[] = ['financial_crisis', 'region_control_loss', 'endgame_threat'];

// V6.7 Phase 3c: mirrors sanitizeTeamPlan's null-on-malformed-shape convention.
const sanitizeTeamEmergencyState = (value: unknown): TeamEmergencyState | null => {
  if (!value || typeof value !== 'object') return null;
  const source = value as Partial<TeamEmergencyState>;
  if (typeof source.declared !== 'boolean') return null;
  const usageByActionId: Record<string, TeamEmergencyActionUsage> = {};
  if (source.usageByActionId && typeof source.usageByActionId === 'object') {
    Object.entries(source.usageByActionId as Record<string, unknown>).forEach(([actionId, raw]) => {
      if (!raw || typeof raw !== 'object') return;
      const usage = raw as Partial<TeamEmergencyActionUsage>;
      usageByActionId[actionId] = {
        actionId,
        usesRemaining: typeof usage.usesRemaining === 'number' && isFinite(usage.usesRemaining) ? Math.max(0, Math.floor(usage.usesRemaining)) : 0,
        lastUsedDay: typeof usage.lastUsedDay === 'number' && isFinite(usage.lastUsedDay) ? Math.floor(usage.lastUsedDay) : -1
      };
    });
  }
  return {
    declared: source.declared,
    reasonTag: EMERGENCY_REASON_TAGS.includes(source.reasonTag as EmergencyReasonTag) ? source.reasonTag as EmergencyReasonTag : null,
    declaredDay: typeof source.declaredDay === 'number' && isFinite(source.declaredDay) ? Math.max(0, Math.floor(source.declaredDay)) : 0,
    reasonSummary: typeof source.reasonSummary === 'string' ? source.reasonSummary : '',
    usageByActionId
  };
};

// V6.7 Phase 3c: always returns a valid object (mirrors sanitizeTeamActionBank), never null.
const sanitizeTeamInitiativeState = (value: unknown): TeamInitiativeState => {
  const defaults: TeamInitiativeState = { value: 0, gainedToday: 0, lastGainDay: 0 };
  if (!value || typeof value !== 'object') return defaults;
  const source = value as Partial<TeamInitiativeState>;
  return {
    value: typeof source.value === 'number' && isFinite(source.value) ? Math.max(0, source.value) : defaults.value,
    gainedToday: typeof source.gainedToday === 'number' && isFinite(source.gainedToday) ? Math.max(0, source.gainedToday) : defaults.gainedToday,
    lastGainDay: typeof source.lastGainDay === 'number' && isFinite(source.lastGainDay) ? Math.floor(source.lastGainDay) : defaults.lastGainDay
  };
};

const sanitizeTeamComboActionEntry = (value: unknown): TeamComboActionEntry | null => {
  if (!value || typeof value !== 'object') return null;
  const source = value as Partial<TeamComboActionEntry>;
  if (typeof source.actorId !== 'string' || typeof source.actionType !== 'string') return null;
  return {
    actorId: source.actorId,
    actionType: source.actionType as AIAction['type'],
    region: typeof source.region === 'string' ? source.region : undefined,
    planId: typeof source.planId === 'string' ? source.planId : undefined,
    turn: typeof source.turn === 'number' && isFinite(source.turn) ? Math.max(0, Math.floor(source.turn)) : 0,
    comboConsumed: Boolean(source.comboConsumed)
  };
};

// V6.7 Phase 3c: always returns a valid object; sequence entries individually validated and
// dropped if malformed (mirrors sanitizeActionTokens), capped at 20 like the live tracking cap.
const sanitizeTeamComboTrackingState = (value: unknown): TeamComboTrackingState => {
  const defaults: TeamComboTrackingState = { sequence: [], comboCountToday: 0, comboCountDay: 0 };
  if (!value || typeof value !== 'object') return defaults;
  const source = value as Partial<TeamComboTrackingState>;
  const sequence = Array.isArray(source.sequence)
    ? source.sequence.map(entry => sanitizeTeamComboActionEntry(entry)).filter((entry): entry is TeamComboActionEntry => Boolean(entry)).slice(-20)
    : [];
  return {
    sequence,
    comboCountToday: typeof source.comboCountToday === 'number' && isFinite(source.comboCountToday) ? Math.max(0, Math.floor(source.comboCountToday)) : 0,
    comboCountDay: typeof source.comboCountDay === 'number' && isFinite(source.comboCountDay) ? Math.max(0, Math.floor(source.comboCountDay)) : 0
  };
};

const normalizePriorityMode = (value: unknown): PriorityMode => {
  return value === 'adaptive' || value === 'manual' ? value : 'balanced';
};

const normalizeDecisionTransparencyVisibilityScope = (value: unknown): DecisionTransparencyVisibilityScope => {
  return value === 'standard' || value === 'human_ai' || value === 'ai_ai' ? value : 'all_modes';
};

const normalizeDecisionTransparencyViewMode = (value: unknown): DecisionTransparencyViewMode => {
  return value === 'advanced' ? 'advanced' : 'simple';
};

const normalizeDecisionTransparencyPanelDensity = (value: unknown): DecisionTransparencyPanelDensity => {
  return value === 'compact' ? 'compact' : 'comfortable';
};

const normalizeDecisionTransparencyGroupView = (value: unknown): DecisionTransparencyGroupView => {
  return value === 'my_team' || value === 'opponents' || value === 'adaptive_only' || value === 'focused_actor'
    ? value
    : 'all_active';
};

const sanitizeManualPriorityWeights = (value: unknown): Record<PriorityDomain, number> => {
  const defaults = createDefaultManualPriorityWeights();
  if (!value || typeof value !== 'object') return defaults;
  return Object.keys(defaults).reduce<Record<PriorityDomain, number>>((acc, key) => {
    const domain = key as PriorityDomain;
    acc[domain] = clampSettingNumber((value as Record<string, unknown>)[domain], defaults[domain], 0, 100);
    return acc;
  }, {} as Record<PriorityDomain, number>);
};

const sanitizeTeamAdaptiveState = (value: unknown): TeamAdaptiveState => {
  const defaults = createDefaultTeamAdaptiveState();
  if (!value || typeof value !== 'object') return defaults;
  const source = value as Partial<TeamAdaptiveState>;
  const phase = source.phase === 'phase1_aggressive' || source.phase === 'phase2_desperate' || source.phase === 'phase3_allIn'
    ? source.phase
    : 'normal';
  const triggeredBy = Array.isArray(source.triggeredBy)
    ? source.triggeredBy.filter(entry => typeof entry === 'string').map(String).slice(0, 8)
    : defaults.triggeredBy;
  const activeModifiers = Array.isArray(source.activeModifiers)
    ? source.activeModifiers.filter(entry => typeof entry === 'string').map(String).slice(0, 12)
    : defaults.activeModifiers;
  return {
    phase,
    daysTriggered: Math.max(0, Math.floor(Number(source.daysTriggered) || 0)),
    dominanceDays: Math.max(0, Math.floor(Number(source.dominanceDays) || 0)),
    teamNetWorthGap: Number.isFinite(source.teamNetWorthGap as number) ? Number(source.teamNetWorthGap) : defaults.teamNetWorthGap,
    teamRegionGap: Number.isFinite(source.teamRegionGap as number) ? Number(source.teamRegionGap) : defaults.teamRegionGap,
    triggeredBy,
    activeModifiers
  };
};

const sanitizeActorRelationshipLabel = (value: unknown): ActorRelationshipLabel => {
  return value === 'your_teammate' || value === 'your_opponent' || value === 'ai_team_teammate' || value === 'ai_team_opponent'
    ? value
    : 'neutral';
};

const sanitizeActorVisibilityGroup = (value: unknown): ActorVisibilityGroup => {
  return value === 'my_team' || value === 'opponents' ? value : 'neutral';
};

const sanitizeDecisionMetricsSnapshot = (value: unknown): DecisionMetricsSnapshot => {
  const defaults = createDefaultDecisionMetricsSnapshot();
  if (!value || typeof value !== 'object') return defaults;
  const source = value as Partial<DecisionMetricsSnapshot>;
  return {
    aggression: clampSettingNumber(source.aggression, defaults.aggression, 0, 100),
    economyFocus: clampSettingNumber(source.economyFocus, defaults.economyFocus, 0, 100),
    objectivePriority: clampSettingNumber(source.objectivePriority, defaults.objectivePriority, 0, 100),
    riskTolerance: clampSettingNumber(source.riskTolerance, defaults.riskTolerance, 0, 100),
    directiveInfluence: clampSettingNumber(source.directiveInfluence, defaults.directiveInfluence, 0, 100),
    supportFocus: clampSettingNumber(source.supportFocus, defaults.supportFocus, 0, 100),
    comebackPressure: clampSettingNumber(source.comebackPressure, defaults.comebackPressure, 0, 100),
    adaptiveIntensity: clampSettingNumber(source.adaptiveIntensity, defaults.adaptiveIntensity, 0, 100)
  };
};

const sanitizeDecisionScoreStages = (value: unknown): DecisionScoreStage[] => {
  if (!Array.isArray(value)) return [];
  return value
    .filter(entry => entry && typeof entry === 'object')
    .map(entry => ({
      id: typeof (entry as DecisionScoreStage).id === 'string' ? (entry as DecisionScoreStage).id : 'stage',
      label: typeof (entry as DecisionScoreStage).label === 'string' ? (entry as DecisionScoreStage).label : 'Stage',
      score: Number((entry as DecisionScoreStage).score) || 0,
      delta: Number((entry as DecisionScoreStage).delta) || 0,
      reason: typeof (entry as DecisionScoreStage).reason === 'string' ? (entry as DecisionScoreStage).reason : ''
    }))
    .slice(0, 12);
};

const sanitizeAiStrategyLabScorePreview = (value: unknown): AiStrategyLabScorePreview | null => {
  if (!value || typeof value !== 'object') return null;
  const source = value as Partial<AiStrategyLabScorePreview>;
  const sanitizeEntries = (entries: unknown) => Array.isArray(entries)
    ? entries
        .filter(entry => entry && typeof entry === 'object')
        .map(entry => ({
          action: typeof (entry as { action?: unknown }).action === 'string'
            ? String((entry as { action?: unknown }).action)
            : 'Action',
          score: Math.round(Number((entry as { score?: unknown }).score) || 0)
        }))
        .slice(0, 3)
    : [];
  const before = sanitizeEntries(source.before);
  const after = sanitizeEntries(source.after);
  return before.length > 0 || after.length > 0
    ? { before, after }
    : null;
};

const sanitizeDecisionSettingVisibilityStates = (value: unknown): DecisionSettingVisibilityState[] => {
  if (!Array.isArray(value)) return [];
  return value
    .filter(entry => entry && typeof entry === 'object' && typeof (entry as DecisionSettingVisibilityState).settingId === 'string')
    .map(entry => ({
      settingId: String((entry as DecisionSettingVisibilityState).settingId),
      label: typeof (entry as DecisionSettingVisibilityState).label === 'string' ? (entry as DecisionSettingVisibilityState).label : String((entry as DecisionSettingVisibilityState).settingId),
      status: (['active_low_impact', 'deprioritized', 'enabled_no_direct_hook', 'disabled', 'ignored'] as SettingVisibilityStatus[]).includes((entry as DecisionSettingVisibilityState).status)
        ? (entry as DecisionSettingVisibilityState).status
        : 'ignored',
      summary: typeof (entry as DecisionSettingVisibilityState).summary === 'string' ? (entry as DecisionSettingVisibilityState).summary : '',
      magnitude: Number((entry as DecisionSettingVisibilityState).magnitude) || 0
    }))
    .slice(0, 32);
};

const sanitizeDecisionTimelinePoint = (value: unknown): DecisionTimelinePoint => {
  const defaults = createDefaultDecisionTimelinePoint();
  if (!value || typeof value !== 'object') return defaults;
  const source = value as Partial<DecisionTimelinePoint>;
  return {
    turnOrDayIndex: Math.max(0, Math.floor(Number(source.turnOrDayIndex) || 0)),
    sequence: Math.max(0, Math.floor(Number(source.sequence) || 0)),
    chosenAction: typeof source.chosenAction === 'string' ? source.chosenAction : defaults.chosenAction,
    decisionMetrics: sanitizeDecisionMetricsSnapshot(source.decisionMetrics),
    prioritizedDomains: Array.isArray(source.prioritizedDomains)
      ? source.prioritizedDomains.filter((entry): entry is PriorityDomain => typeof entry === 'string' && entry in PRIORITY_DOMAIN_LABELS)
      : defaults.prioritizedDomains,
    deprioritizedDomains: Array.isArray(source.deprioritizedDomains)
      ? source.deprioritizedDomains.filter((entry): entry is PriorityDomain => typeof entry === 'string' && entry in PRIORITY_DOMAIN_LABELS)
      : defaults.deprioritizedDomains,
    adaptiveIntensity: clampSettingNumber(source.adaptiveIntensity, defaults.adaptiveIntensity, 0, 100),
    timestamp: typeof source.timestamp === 'number' ? source.timestamp : defaults.timestamp
  };
};

const sanitizeActorAdaptiveEffectState = (
  value: unknown,
  fallbackActorId = '',
  fallbackTeamId = ''
): ActorAdaptiveEffectState => {
  const defaults = createDefaultActorAdaptiveEffectState();
  if (!value || typeof value !== 'object') {
    return { ...defaults, actorId: fallbackActorId, teamId: fallbackTeamId };
  }
  const source = value as Partial<ActorAdaptiveEffectState>;
  const appliedAdaptiveModifiers = Array.isArray(source.appliedAdaptiveModifiers)
    ? source.appliedAdaptiveModifiers
        .filter(entry => entry && typeof entry === 'object')
        .map(entry => ({
          key: typeof (entry as ActorAdaptiveModifierEntry).key === 'string' ? (entry as ActorAdaptiveModifierEntry).key : 'modifier',
          label: typeof (entry as ActorAdaptiveModifierEntry).label === 'string' ? (entry as ActorAdaptiveModifierEntry).label : 'Modifier',
          percent: Number((entry as ActorAdaptiveModifierEntry).percent) || 0,
          reason: typeof (entry as ActorAdaptiveModifierEntry).reason === 'string' ? (entry as ActorAdaptiveModifierEntry).reason : ''
        }))
        .slice(0, 12)
    : defaults.appliedAdaptiveModifiers;
  const adaptiveWeightSummary = typeof source.adaptiveWeightSummary === 'object' && source.adaptiveWeightSummary !== null
    ? Object.entries(source.adaptiveWeightSummary).reduce<Record<string, number>>((acc, [key, amount]) => {
        if (typeof amount === 'number' && isFinite(amount)) {
          acc[key] = amount;
        }
        return acc;
      }, {})
    : defaults.adaptiveWeightSummary;
  return {
    actorId: typeof source.actorId === 'string' ? source.actorId : fallbackActorId,
    teamId: typeof source.teamId === 'string' ? source.teamId : fallbackTeamId,
    isAdaptiveAffected: Boolean(source.isAdaptiveAffected),
    adaptiveSourceTeamPhase: source.adaptiveSourceTeamPhase === 'phase1_aggressive' || source.adaptiveSourceTeamPhase === 'phase2_desperate' || source.adaptiveSourceTeamPhase === 'phase3_allIn'
      ? source.adaptiveSourceTeamPhase
      : 'normal',
    adaptiveReasonSummary: typeof source.adaptiveReasonSummary === 'string' ? source.adaptiveReasonSummary : defaults.adaptiveReasonSummary,
    lastAdaptiveUpdateTurn: Math.max(0, Math.floor(Number(source.lastAdaptiveUpdateTurn) || 0)),
    appliedAdaptiveModifiers,
    adaptiveWeightSummary
  };
};

const sanitizeTeamAdaptiveSourceSnapshot = (value: unknown): TeamAdaptiveSourceSnapshot => {
  const defaults = createDefaultTeamAdaptiveSourceSnapshot();
  if (!value || typeof value !== 'object') return defaults;
  const source = value as Partial<TeamAdaptiveSourceSnapshot>;
  return {
    teamId: typeof source.teamId === 'string' ? source.teamId : defaults.teamId,
    teamName: typeof source.teamName === 'string' ? source.teamName : defaults.teamName,
    phase: source.phase === 'phase1_aggressive' || source.phase === 'phase2_desperate' || source.phase === 'phase3_allIn'
      ? source.phase
      : 'normal',
    daysTriggered: Math.max(0, Math.floor(Number(source.daysTriggered) || 0)),
    triggeredBy: Array.isArray(source.triggeredBy) ? source.triggeredBy.filter(item => typeof item === 'string').map(String).slice(0, 8) : defaults.triggeredBy,
    teamNetWorthGap: Number(source.teamNetWorthGap) || 0,
    teamRegionGap: Number(source.teamRegionGap) || 0,
    activeModifiers: Array.isArray(source.activeModifiers) ? source.activeModifiers.filter(item => typeof item === 'string').map(String).slice(0, 12) : defaults.activeModifiers,
    summary: typeof source.summary === 'string' ? source.summary : defaults.summary
  };
};

const sanitizeActorDecisionOverview = (value: unknown): ActorDecisionOverview => {
  const defaults = createDefaultActorDecisionOverview();
  if (!value || typeof value !== 'object') return defaults;
  const source = value as Partial<ActorDecisionOverview>;
  return {
    actorName: typeof source.actorName === 'string' ? source.actorName : defaults.actorName,
    teamName: typeof source.teamName === 'string' ? source.teamName : defaults.teamName,
    relationshipLabel: sanitizeActorRelationshipLabel(source.relationshipLabel),
    roleLabel: typeof source.roleLabel === 'string' ? source.roleLabel : defaults.roleLabel,
    roleModeLabel: typeof source.roleModeLabel === 'string' ? source.roleModeLabel : defaults.roleModeLabel,
    economyStateLabel: typeof source.economyStateLabel === 'string' ? source.economyStateLabel : defaults.economyStateLabel,
    supportBalanceLabel: typeof source.supportBalanceLabel === 'string' ? source.supportBalanceLabel : defaults.supportBalanceLabel,
    modeLabel: typeof source.modeLabel === 'string' ? source.modeLabel : defaults.modeLabel,
    turnLabel: typeof source.turnLabel === 'string' ? source.turnLabel : defaults.turnLabel,
    chosenAction: typeof source.chosenAction === 'string' ? source.chosenAction : defaults.chosenAction,
    explanation: typeof source.explanation === 'string' ? source.explanation : defaults.explanation,
    compactDecisionLine: typeof source.compactDecisionLine === 'string' ? source.compactDecisionLine : defaults.compactDecisionLine,
    topReasons: Array.isArray(source.topReasons) ? source.topReasons.filter(item => typeof item === 'string').map(String).slice(0, 8) : defaults.topReasons,
    topSettingLabels: Array.isArray(source.topSettingLabels) ? source.topSettingLabels.filter(item => typeof item === 'string').map(String).slice(0, 8) : defaults.topSettingLabels,
    prioritizedDomains: Array.isArray(source.prioritizedDomains)
      ? source.prioritizedDomains.filter((entry): entry is PriorityDomain => typeof entry === 'string' && entry in PRIORITY_DOMAIN_LABELS)
      : defaults.prioritizedDomains,
    deprioritizedDomains: Array.isArray(source.deprioritizedDomains)
      ? source.deprioritizedDomains.filter((entry): entry is PriorityDomain => typeof entry === 'string' && entry in PRIORITY_DOMAIN_LABELS)
      : defaults.deprioritizedDomains,
    activeModifierLabels: Array.isArray(source.activeModifierLabels) ? source.activeModifierLabels.filter(item => typeof item === 'string').map(String).slice(0, 12) : defaults.activeModifierLabels,
    adaptiveStatusLabel: typeof source.adaptiveStatusLabel === 'string' ? source.adaptiveStatusLabel : defaults.adaptiveStatusLabel
  };
};

const sanitizeAiDecisionCompactSummary = (value: unknown): AiDecisionCompactSummary => {
  const defaults = createDefaultAiDecisionCompactSummary();
  if (!value || typeof value !== 'object') return defaults;
  const source = value as Partial<AiDecisionCompactSummary>;
  return {
    decisionLine: typeof source.decisionLine === 'string' ? source.decisionLine : defaults.decisionLine,
    chosenActionLine: typeof source.chosenActionLine === 'string' ? source.chosenActionLine : defaults.chosenActionLine,
    topReasonLine: typeof source.topReasonLine === 'string' ? source.topReasonLine : defaults.topReasonLine,
    winConditionLine: typeof source.winConditionLine === 'string' ? source.winConditionLine : defaults.winConditionLine,
    economyLine: typeof source.economyLine === 'string' ? source.economyLine : defaults.economyLine,
    roleModeLine: typeof source.roleModeLine === 'string' ? source.roleModeLine : defaults.roleModeLine,
    supportLine: typeof source.supportLine === 'string' ? source.supportLine : defaults.supportLine,
    directiveLine: typeof source.directiveLine === 'string' ? source.directiveLine : defaults.directiveLine,
    syncLine: typeof source.syncLine === 'string' ? source.syncLine : defaults.syncLine,
    adaptiveLine: typeof source.adaptiveLine === 'string' ? source.adaptiveLine : defaults.adaptiveLine,
    confidenceLine: typeof source.confidenceLine === 'string' ? source.confidenceLine : defaults.confidenceLine,
    modifiersLine: typeof source.modifiersLine === 'string' ? source.modifiersLine : defaults.modifiersLine
  };
};

const sanitizeDecisionCandidateTrace = (value: unknown): AiDecisionCandidateTrace | null => {
  if (!value || typeof value !== 'object' || typeof (value as AiDecisionCandidateTrace).type !== 'string') return null;
  const source = value as Partial<AiDecisionCandidateTrace>;
  return {
    type: String(source.type),
    description: typeof source.description === 'string' ? source.description : String(source.type),
    rawScore: Number(source.rawScore) || 0,
    adjustedScore: Number(source.adjustedScore) || 0,
    factorWeights: typeof source.factorWeights === 'object' && source.factorWeights !== null
      ? Object.entries(source.factorWeights).reduce<Record<string, number>>((acc, [key, amount]) => {
          if (typeof amount === 'number' && isFinite(amount)) {
            acc[key] = amount;
          }
          return acc;
        }, {})
      : {},
    settingContributions: Array.isArray(source.settingContributions)
      ? source.settingContributions.slice(0, 20)
      : [],
    reason: typeof source.reason === 'string' ? source.reason : '',
    relationshipLabel: sanitizeActorRelationshipLabel(source.relationshipLabel),
    teamName: typeof source.teamName === 'string' ? source.teamName : '',
    actorOverview: sanitizeActorDecisionOverview(source.actorOverview),
    decisionMetrics: sanitizeDecisionMetricsSnapshot(source.decisionMetrics),
    adaptiveSourceSnapshot: source.adaptiveSourceSnapshot ? sanitizeTeamAdaptiveSourceSnapshot(source.adaptiveSourceSnapshot) : null,
    actorAdaptiveEffectState: sanitizeActorAdaptiveEffectState(source.actorAdaptiveEffectState),
    scoreStages: sanitizeDecisionScoreStages(source.scoreStages),
    inactiveSettingStates: sanitizeDecisionSettingVisibilityStates(source.inactiveSettingStates),
    rejectedReasonSummary: Array.isArray(source.rejectedReasonSummary) ? source.rejectedReasonSummary.filter(item => typeof item === 'string').map(String).slice(0, 8) : [],
    timelinePoint: sanitizeDecisionTimelinePoint(source.timelinePoint),
    aiStrategyLabScorePreview: sanitizeAiStrategyLabScorePreview(source.aiStrategyLabScorePreview),
    data: source.data
  };
};

const sanitizeDecisionTrace = (value: unknown): AiDecisionTrace | null => {
  if (!value || typeof value !== 'object') return null;
  const source = value as Partial<AiDecisionTrace>;
  if (typeof source.actorId !== 'string' || typeof source.teamId !== 'string') return null;
  return {
    actorId: source.actorId,
    teamId: source.teamId,
    mode: source.mode === 'ai' || source.mode === 'grand_tour' || source.mode === 'team_human_ai_vs_ai_ai' || source.mode === 'team_ai_vs_ai' ? source.mode : 'ai',
    turnOrDayIndex: Math.max(0, Math.floor(Number(source.turnOrDayIndex) || 0)),
    sequence: Math.max(0, Math.floor(Number(source.sequence) || 0)),
    chosenAction: typeof source.chosenAction === 'string' ? source.chosenAction : 'end_turn',
    explanation: typeof source.explanation === 'string' ? source.explanation : '',
    activeModifiers: Array.isArray(source.activeModifiers) ? source.activeModifiers.filter(item => typeof item === 'string').map(String).slice(0, 20) : [],
    prioritizedDomains: Array.isArray(source.prioritizedDomains)
      ? source.prioritizedDomains.filter((entry): entry is PriorityDomain => typeof entry === 'string' && entry in PRIORITY_DOMAIN_LABELS)
      : [],
    deprioritizedDomains: Array.isArray(source.deprioritizedDomains)
      ? source.deprioritizedDomains.filter((entry): entry is PriorityDomain => typeof entry === 'string' && entry in PRIORITY_DOMAIN_LABELS)
      : [],
    reasons: Array.isArray(source.reasons) ? source.reasons.filter(item => typeof item === 'string').map(String).slice(0, 10) : [],
    factorWeights: typeof source.factorWeights === 'object' && source.factorWeights !== null
      ? Object.entries(source.factorWeights).reduce<Record<string, number>>((acc, [key, amount]) => {
          if (typeof amount === 'number' && isFinite(amount)) {
            acc[key] = amount;
          }
          return acc;
        }, {})
      : {},
    settingContributions: Array.isArray(source.settingContributions)
      ? source.settingContributions
          .filter(entry => entry && typeof entry === 'object' && typeof (entry as DecisionContribution).settingId === 'string')
          .map(entry => ({
            settingId: String((entry as DecisionContribution).settingId),
            label: typeof (entry as DecisionContribution).label === 'string' ? (entry as DecisionContribution).label : String((entry as DecisionContribution).settingId),
            domain: typeof (entry as DecisionContribution).domain === 'string' && (entry as DecisionContribution).domain in PRIORITY_DOMAIN_LABELS
              ? (entry as DecisionContribution).domain as PriorityDomain
              : 'economy',
            weightDelta: Number((entry as DecisionContribution).weightDelta) || 0,
            reason: typeof (entry as DecisionContribution).reason === 'string' ? (entry as DecisionContribution).reason : '',
            prioritized: Boolean((entry as DecisionContribution).prioritized),
            strengthLabel: ((entry as DecisionContribution).strengthLabel === 'Low' || (entry as DecisionContribution).strengthLabel === 'High')
              ? (entry as DecisionContribution).strengthLabel
              : 'Medium'
          }))
          .slice(0, 40)
      : [],
    candidates: Array.isArray(source.candidates)
      ? source.candidates.map(sanitizeDecisionCandidateTrace).filter((candidate): candidate is AiDecisionCandidateTrace => Boolean(candidate)).slice(0, 12)
      : [],
    alternativeActions: Array.isArray(source.alternativeActions) ? source.alternativeActions.filter(item => typeof item === 'string').map(String).slice(0, 8) : [],
    priorityFlow: Array.isArray(source.priorityFlow)
      ? source.priorityFlow
          .filter(entry => entry && typeof entry === 'object' && typeof (entry as PriorityResolutionEntry).domain === 'string')
          .map(entry => ({
            domain: typeof (entry as PriorityResolutionEntry).domain === 'string' && (entry as PriorityResolutionEntry).domain in PRIORITY_DOMAIN_LABELS
              ? (entry as PriorityResolutionEntry).domain as PriorityDomain
              : 'economy',
            before: Number((entry as PriorityResolutionEntry).before) || 0,
            after: Number((entry as PriorityResolutionEntry).after) || 0,
            reason: typeof (entry as PriorityResolutionEntry).reason === 'string' ? (entry as PriorityResolutionEntry).reason : '',
            prioritized: Boolean((entry as PriorityResolutionEntry).prioritized)
          }))
          .slice(0, 20)
      : [],
    relationshipLabel: sanitizeActorRelationshipLabel(source.relationshipLabel),
    teamName: typeof source.teamName === 'string' ? source.teamName : '',
    actorOverview: sanitizeActorDecisionOverview(source.actorOverview),
    decisionMetrics: sanitizeDecisionMetricsSnapshot(source.decisionMetrics),
    adaptiveSourceSnapshot: source.adaptiveSourceSnapshot ? sanitizeTeamAdaptiveSourceSnapshot(source.adaptiveSourceSnapshot) : null,
    actorAdaptiveEffectState: sanitizeActorAdaptiveEffectState(source.actorAdaptiveEffectState, source.actorId, source.teamId),
    scoreStages: sanitizeDecisionScoreStages(source.scoreStages),
    inactiveSettingStates: sanitizeDecisionSettingVisibilityStates(source.inactiveSettingStates),
    rejectedReasonSummary: Array.isArray(source.rejectedReasonSummary) ? source.rejectedReasonSummary.filter(item => typeof item === 'string').map(String).slice(0, 8) : [],
    timelinePoint: sanitizeDecisionTimelinePoint(source.timelinePoint),
    compactSummary: sanitizeAiDecisionCompactSummary(source.compactSummary),
    aiStrategyLabScorePreview: sanitizeAiStrategyLabScorePreview(source.aiStrategyLabScorePreview),
    timestamp: typeof source.timestamp === 'number' ? source.timestamp : Date.now()
  };
};

const sanitizeDecisionState = (value: unknown): DecisionState => {
  const defaults = createDefaultDecisionState();
  if (!value || typeof value !== 'object') return defaults;
  const source = value as Partial<DecisionState>;
  const lastByActor = typeof source.lastByActor === 'object' && source.lastByActor !== null
    ? Object.entries(source.lastByActor).reduce<Record<string, ActorInterpretabilityState>>((acc, [actorId, entry]) => {
        const candidateEntry = entry as ActorInterpretabilityState & { lastTrace?: AiDecisionTrace | null };
        const sanitizedTrace = sanitizeDecisionTrace(candidateEntry?.currentTrace || candidateEntry?.lastTrace);
        if (!sanitizedTrace) return acc;
        acc[actorId] = {
          actorId,
          teamId: typeof candidateEntry?.teamId === 'string' ? candidateEntry.teamId : sanitizedTrace.teamId,
          summary: typeof candidateEntry?.summary === 'string' ? candidateEntry.summary : sanitizedTrace.explanation,
          currentTrace: sanitizedTrace,
          lastTrace: sanitizedTrace,
          lastUpdatedTurn: Math.max(0, Math.floor(Number(candidateEntry?.lastUpdatedTurn) || sanitizedTrace.turnOrDayIndex || 0)),
          overview: sanitizeActorDecisionOverview(candidateEntry?.overview || sanitizedTrace.actorOverview),
          actorAdaptiveEffectState: sanitizeActorAdaptiveEffectState(candidateEntry?.actorAdaptiveEffectState || sanitizedTrace.actorAdaptiveEffectState, actorId, sanitizedTrace.teamId),
          adaptiveSourceSnapshot: sanitizeTeamAdaptiveSourceSnapshot(candidateEntry?.adaptiveSourceSnapshot || sanitizedTrace.adaptiveSourceSnapshot),
          lastVisibleDecisionSnapshot: sanitizeDecisionTimelinePoint(candidateEntry?.lastVisibleDecisionSnapshot || sanitizedTrace.timelinePoint),
          visibilityGroup: sanitizeActorVisibilityGroup(candidateEntry?.visibilityGroup)
        };
        return acc;
      }, {})
    : defaults.lastByActor;
  const historyByActor = typeof source.historyByActor === 'object' && source.historyByActor !== null
    ? Object.entries(source.historyByActor).reduce<Record<string, AiDecisionTrace[]>>((acc, [actorId, entries]) => {
        const sanitizedEntries = Array.isArray(entries)
          ? entries.map(sanitizeDecisionTrace).filter((trace): trace is AiDecisionTrace => Boolean(trace)).slice(-60)
          : [];
        acc[actorId] = sanitizedEntries;
        return acc;
      }, {})
    : defaults.historyByActor;
  return {
    sequence: Math.max(0, Math.floor(Number(source.sequence) || 0)),
    lastByActor,
    historyByActor
  };
};

const createDefaultTeamState = (
  id: string,
  name: string,
  actorIds: string[],
  color: string
): TeamState => ({
  id,
  name,
  actorIds,
  messageLog: [],
  activeReservations: [],
  teamGoals: [],
  scoreBreakdown: createDefaultTeamScoreBreakdown(),
  contributionByActor: actorIds.reduce<Record<string, ActorContributionStats>>((acc, actorId) => {
    acc[actorId] = createDefaultContributionStats();
    return acc;
  }, {}),
  recentPerformanceByActor: createDefaultRecentPerformanceByActor(actorIds),
  realizedPerformanceByActor: createDefaultRealizedPerformanceByActor(actorIds),
  supportLedger: createDefaultTeamSupportLedger(),
  adaptiveState: createDefaultTeamAdaptiveState(),
  teamActionBank: createDefaultTeamActionBankState(),
  actionTokens: [],
  activeTeamPlan: null,
  teamPlanHistory: [],
  activeThreatTarget: null,
  activeEmergency: null,
  teamInitiative: { value: 0, gainedToday: 0, lastGainDay: 0 },
  comboTracking: { sequence: [], comboCountToday: 0, comboCountDay: 0 },
  color,
  sequences: [],
  phaseSequenceAssignments: [],
  treasury: createDefaultTeamTreasuryState(id),
  governorExceptions: [],
  overseer: createDefaultTeamOverseerState()
});

const getTeamMessageExpiry = (type: TeamMessageType) => {
  if (type === 'combo_setup' || type === 'request_cover') {
    return TEAM_MESSAGE_DURATION_EXTENDED;
  }
  return TEAM_MESSAGE_DURATION_DEFAULT;
};

