    const aiSoloRegions = soloControlSnapshot.totalControlled.ai || 0;
    const soloMetricValues: Record<WinMetric, { player: number; ai: number }> = {
      money: { player: projectedPlayer.money, ai: projectedAi.money },
      netWorth: { player: updatedPlayerWorth, ai: updatedAiWorth },
      regions: { player: playerSoloRegions, ai: aiSoloRegions }
    };
    const soloPrimaryPlayerValue = soloMetricValues[gameSettings.winCondition].player;
    const soloPrimaryAiValue = soloMetricValues[gameSettings.winCondition].ai;
    const playerDominance = gameSettings.winCondition === 'regions'
      ? (playerSoloRegions >= Math.max(REGION_CONTROL_MAJORITY, aiSoloRegions + 4) ? gameState.dominanceTracker.player + 1 : 0)
      : (soloPrimaryAiValue > 0 && soloPrimaryPlayerValue / soloPrimaryAiValue >= 5 ? gameState.dominanceTracker.player + 1 : 0);
    const aiDominance = gameSettings.winCondition === 'regions'
      ? (aiSoloRegions >= Math.max(REGION_CONTROL_MAJORITY, playerSoloRegions + 4) ? gameState.dominanceTracker.ai + 1 : 0)
      : (soloPrimaryPlayerValue > 0 && soloPrimaryAiValue / soloPrimaryPlayerValue >= 5 ? gameState.dominanceTracker.ai + 1 : 0);
    dispatchGameState({ type: 'SET_DOMINANCE_TRACKER', payload: { player: playerDominance, ai: aiDominance } });

