                          <input type="range" min="0" max="50" value={Math.round(gameSettings.teamAiEndgameOverrideBias * 100)} onChange={(e) => setGameSettings(prev => ({ ...prev, teamAiEndgameOverrideBias: parseInt(e.target.value) / 100 }))} className="w-full" />
